use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PlayerScore {
    pub name: String,
    pub points: i32,
    pub wins: u32,
    pub losses: u32,
}

pub fn top_players(entries: &[PlayerScore], limit: usize) -> Vec<String> {
    let mut best: HashMap<String, PlayerScore> = HashMap::new();

    for e in entries {
        best.entry(e.name.clone())
            .and_modify(|cur| {
                if e.points >= cur.points {
                    *cur = e.clone();
                }
            })
            .or_insert_with(|| e.clone());
    }

    let mut players: Vec<PlayerScore> = best.into_values().collect();
    players.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.name.cmp(&b.name))
    });

    players
        .into_iter()
        .take(limit)
        .map(|p| p.name)
        .collect()
}

#[cfg(test)]
mod tests {
