    }

    #[test]
    fn keeps_best_entry_per_player_using_all_tiebreaks() {
        let entries = vec![
            p("Mia", 20, 5, 4),
            p("Mia", 20, 6, 9),
            p("Mia", 20, 6, 2),
            p("Nia", 18, 9, 0),
            p("Nia", 21, 1, 8),
            p("Omar", 20, 6, 2),
        ];

        assert_eq!(top_players(&entries, 3), vec!["Mia", "Omar", "Nia"]);
    }

    #[test]
    fn duplicate_names_are_case_insensitive_and_preserve_first_seen_spelling() {
        let entries = vec![
            p("alice", 10, 1, 0),
            p("Bob", 11, 1, 0),
            p("ALICE", 12, 1, 0),
            p("bob", 9, 9, 0),
            p("cara", 12, 1, 1),
        ];

        assert_eq!(top_players(&entries, 5), vec!["ALICE", "cara", "Bob"]);
    }

    #[test]
    fn limit_zero_and_large_limit_behave() {
        let entries = vec![p("Kai", 3, 0, 0), p("Luz", 4, 0, 0)];
        assert!(top_players(&entries, 0).is_empty());
        assert_eq!(top_players(&entries, 10), vec!["Luz", "Kai"]);
    }
}

