use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub day: &'static str,
    pub rep: &'static str,
    pub region: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn daily_region_report(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        if sale.amount <= 0 {
            continue;
        }
        *totals.entry(sale.day).or_insert(0) += sale.amount;
        *counts.entry(sale.day).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    for (day, total) in totals {
        let count = counts.get(day).copied().unwrap_or(0);
        lines.push(format!("{}: total={}, orders={}", day, total, count));
    }

    if lines.is_empty() {
        "no sales".to_string()
    } else {
        lines.join("\n")
    }
}

#[cfg(test)]
