#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u32,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u32>,
}

impl PartialConfig {
    pub fn new() -> Self {
        Self::default()
    }
}

pub fn merge_config(
    defaults: &Config,
    env: Option<&PartialConfig>,
    overrides: Option<&PartialConfig>,
) -> Config {
    let env = env.cloned().unwrap_or_default();
    let overrides = overrides.cloned().unwrap_or_default();

    Config {
        host: overrides
            .host
            .or(env.host)
            .unwrap_or_else(|| defaults.host.clone()),
        port: overrides.port.or(env.port).unwrap_or(defaults.port),
        use_tls: env.use_tls.or(overrides.use_tls).unwrap_or(defaults.use_tls),
        timeout_ms: defaults.timeout_ms,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn base() -> Config {
        Config {
            host: "localhost".into(),
            port: 8080,
            use_tls: false,
            timeout_ms: 1000,
        }
    }

    #[test]
    fn override_wins_over_env_and_defaults() {
        let defaults = base();
        let env = PartialConfig {
            host: Some("env.internal".into()),
            port: Some(9000),
            use_tls: Some(true),
            timeout_ms: Some(2000),
        };
        let overrides = PartialConfig {
            host: Some("cli.example.com".into()),
            port: None,
            use_tls: Some(false),
            timeout_ms: Some(5000),
        };

        let merged = merge_config(&defaults, Some(&env), Some(&overrides));
        assert_eq!(merged.host, "cli.example.com");
        assert_eq!(merged.port, 9000);
        assert!(!merged.use_tls);
        assert_eq!(merged.timeout_ms, 5000);
    }

    #[test]
    fn env_fills_missing_values_before_defaults() {
        let defaults = base();
        let env = PartialConfig {
            host: None,
            port: Some(7000),
            use_tls: Some(true),
            timeout_ms: Some(1500),
        };

        let merged = merge_config(&defaults, Some(&env), None);
        assert_eq!(merged.host, "localhost");
        assert_eq!(merged.port, 7000);
        assert!(merged.use_tls);
        assert_eq!(merged.timeout_ms, 1500);
    }

    #[test]
    fn defaults_are_used_when_no_layer_sets_a_field() {
        let defaults = base();
        let merged = merge_config(&defaults, None, Some(&PartialConfig::new()));
        assert_eq!(merged, defaults);
    }
}

