    pub approved: bool,
}

pub fn team_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for e in entries {
        let row = totals.entry(e.team).or_insert((0, 0));
        row.0 += e.hours;
        row.1 += 1;
    }

    let mut lines = Vec::new();
    for (team, (hours, count)) in totals {
        let avg = hours as f32 / count as f32;
        lines.push(format!("{}|total={}|avg={}", team, hours, avg as u32));
    }

    lines.join("\n")
}

