#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Submitted,
    Approved,
    Rejected,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Draft, Event::Submit) => Status::Submitted,
        (Status::Submitted, Event::Approve) => Status::Approved,
        (Status::Submitted, Event::Reject) => Status::Rejected,
        (Status::Rejected, Event::Submit) => Status::Submitted,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn happy_path_reaches_approved() {
        let mut s = Status::Draft;
        s = apply_event(s, Event::Submit);
        s = apply_event(s, Event::Approve);
        assert_eq!(s, Status::Approved);
    }

    #[test]
    fn reject_then_revise_returns_to_draft() {
        let mut s = Status::Draft;
        s = apply_event(s, Event::Submit);
        s = apply_event(s, Event::Reject);
        s = apply_event(s, Event::Revise);
        assert_eq!(s, Status::Draft);
    }

    #[test]
    fn approved_item_stays_approved_on_revise() {
        let s = apply_event(Status::Approved, Event::Revise);
        assert_eq!(s, Status::Approved);
    }

    #[test]
    fn rejected_item_can_be_resubmitted_only_after_revise() {
        let s = apply_event(Status::Rejected, Event::Submit);
        assert_eq!(s, Status::Rejected);
    }
}

