#[derive(Debug, PartialEq, Eq)]
pub struct Settings {
    pub host: String,
    pub port: u16,
    pub secure: bool,
}

pub fn parse_settings(input: &str) -> Result<Settings, String> {
    let mut host = None;
    let mut port = None;
    let mut secure = false;

    for raw in input.lines() {
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let (key, value) = line
            .split_once('=')
            .ok_or_else(|| format!("invalid line: {}", line))?;

        match key.trim() {
            "host" => host = Some(value.trim().to_string()),
            "port" => {
                port = Some(value.trim().parse::<u16>().map_err(|_| "invalid port".to_string())?)
            }
            "secure" => secure = value.trim() == "true",
            _ => return Err(format!("unknown key: {}", key.trim())),
        }
    }

    Ok(Settings {
        host: host.unwrap_or_default(),
        port: port.unwrap_or(80),
        secure,
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_config_with_comments_and_spaces() {
        let cfg = "\n# service config\nhost = example.com\nport = 443\nsecure = true\n";
        let parsed = parse_settings(cfg).unwrap();
        assert_eq!(parsed.host, "example.com");
        assert_eq!(parsed.port, 443);
        assert!(parsed.secure);
    }

    #[test]
    fn rejects_empty_host_even_when_key_present() {
        let err = parse_settings("host =   \nport=80\n").unwrap_err();
        assert_eq!(err, "host cannot be empty");
    }

    #[test]
    fn rejects_non_boolean_secure_values() {
        let err = parse_settings("host=x\nsecure=yes\n").unwrap_err();
        assert_eq!(err, "invalid secure");
    }

    #[test]
    fn requires_host_to_be_provided() {
        let err = parse_settings("port=9000\nsecure=false\n").unwrap_err();
        assert_eq!(err, "missing host");
    }

    #[test]
    fn default_port_is_used_when_missing() {
        let parsed = parse_settings("host=local\nsecure=false\n").unwrap();
        assert_eq!(parsed.port, 80);
        assert!(!parsed.secure);
    }
}

