#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Todo,
    InProgress,
    Blocked,
    Done,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Reset,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Todo, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::Todo,
        (Status::InProgress, Event::Complete) => Status::Done,
        (_, Event::Reset) => Status::Todo,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn normal_flow_reaches_done() {
        let s = apply_event(Status::Todo, Event::Start);
        let s = apply_event(s, Event::Complete);
        assert_eq!(s, Status::Done);
    }

    #[test]
    fn unblock_returns_to_in_progress() {
        let s = apply_event(Status::Todo, Event::Start);
        let s = apply_event(s, Event::Block);
        let s = apply_event(s, Event::Unblock);
        assert_eq!(s, Status::InProgress);
    }

    #[test]
    fn done_is_stable_except_reset() {
        assert_eq!(apply_event(Status::Done, Event::Start), Status::Done);
        assert_eq!(apply_event(Status::Done, Event::Block), Status::Done);
        assert_eq!(apply_event(Status::Done, Event::Complete), Status::Done);
        assert_eq!(apply_event(Status::Done, Event::Reset), Status::Todo);
    }
}

