#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_secs: Option<u32>,
}

pub fn merge_config(
    defaults: &Config,
    profile: &PartialConfig,
    env: &PartialConfig,
    force_disable_tls: bool,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(host) = profile.host.as_ref() {
        merged.host = host.clone();
    }
    if let Some(port) = profile.port {
        merged.port = port;
    }
    if let Some(use_tls) = profile.use_tls {
        merged.use_tls = use_tls;
    }
    if let Some(timeout_secs) = profile.timeout_secs {
        merged.timeout_secs = timeout_secs;
    }

    if let Some(port) = env.port {
        merged.port = port;
    }
    if let Some(use_tls) = env.use_tls {
        merged.use_tls = use_tls;
    }
    if let Some(timeout_secs) = env.timeout_secs {
        merged.timeout_secs = timeout_secs;
    }

    if force_disable_tls {
        merged.use_tls = false;
    }

    merged
}

