#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        _ => status,
    }
}

pub fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = apply_event(status, event);
    }
    status
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolved_ticket_can_be_closed() {
        let status = apply_events(Status::Open, &[Event::Start, Event::Resolve, Event::Close]);
        assert_eq!(status, Status::Closed);
    }

    #[test]
    fn closed_ticket_can_be_reopened() {
        let status = apply_events(Status::Open, &[Event::Start, Event::Resolve, Event::Close, Event::Reopen]);
        assert_eq!(status, Status::Open);
    }

    #[test]
    fn reopened_ticket_can_be_worked_and_closed_again() {
        let status = apply_events(
            Status::Open,
            &[
                Event::Start,
                Event::Resolve,
                Event::Close,
                Event::Reopen,
                Event::Start,
                Event::Resolve,
                Event::Close,
            ],
        );
        assert_eq!(status, Status::Closed);
    }
}

pub fn can_book(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    let (start, end) = candidate;
    if start >= end {
        return false;
    }

    existing.iter().all(|&(a, b)| {
        if a >= b {
            return false;
        }
        end < a || start > b
    })
}

