    }

    #[test]
    fn allows_back_to_back_booking() {
        assert!(can_book(&[(9, 11)], (11, 13)));
        assert!(can_book(&[(11, 13)], (9, 11)));
    }

    #[test]
    fn rejects_true_overlap() {
        assert!(!can_book(&[(9, 11)], (10, 12)));
        assert!(!can_book(&[(9, 11)], (8, 10)));
    }

