#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Team {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub goals_for: i32,
    pub goals_against: i32,
    pub fair_play_penalty: i32,
}

impl Team {
    fn points(&self) -> u32 {
        self.wins * 3 + self.draws
    }

    fn goal_diff(&self) -> i32 {
        self.goals_for - self.goals_against
    }
}

pub fn rank_teams(teams: &[Team]) -> Vec<&'static str> {
    let mut teams = teams.to_vec();
    teams.sort_by_key(|t| {
        (
            t.points(),
            t.goal_diff(),
            t.goals_for,
            t.fair_play_penalty,
            t.name,
        )
    });
    teams.into_iter().map(|t| t.name).collect()
}

