#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TaskState {
    Todo,
    InProgress { blocked: bool },
    Done { verified: bool },
    Archived,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    Start,
    Block,
    Unblock,
    Finish,
    Verify,
    Archive,
    Restore,
}

pub fn apply_action(state: TaskState, action: Action) -> TaskState {
    match (state, action) {
        (TaskState::Todo, Action::Start) => TaskState::InProgress { blocked: false },
        (TaskState::InProgress { .. }, Action::Block) => TaskState::InProgress { blocked: true },
        (TaskState::InProgress { .. }, Action::Unblock) => TaskState::InProgress { blocked: false },
        (TaskState::InProgress { blocked: false }, Action::Finish) => TaskState::Done { verified: true },
        (TaskState::Done { .. }, Action::Verify) => TaskState::Done { verified: false },
        (TaskState::Done { .. }, Action::Archive) => TaskState::Archived,
        (TaskState::Archived, Action::Restore) => TaskState::Done { verified: true },
        (s, _) => s,
    }
}

pub fn apply_actions(mut state: TaskState, actions: &[Action]) -> TaskState {
    for action in actions {
        state = apply_action(state, action.clone());
    }
    state
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn finish_from_unblocked_progress_is_unverified_done() {
        let state = apply_action(TaskState::InProgress { blocked: false }, Action::Finish);
        assert_eq!(state, TaskState::Done { verified: false });
    }

    #[test]
    fn verify_marks_done_as_verified() {
        let state = apply_action(TaskState::Done { verified: false }, Action::Verify);
        assert_eq!(state, TaskState::Done { verified: true });
    }

    #[test]
    fn restore_from_archive_returns_todo() {
        let state = apply_action(TaskState::Archived, Action::Restore);
        assert_eq!(state, TaskState::Todo);
    }

    #[test]
    fn blocked_workflow_cannot_finish_until_unblocked() {
        let actions = [Action::Start, Action::Block, Action::Finish, Action::Unblock, Action::Finish];
        let state = apply_actions(TaskState::Todo, &actions);
        assert_eq!(state, TaskState::Done { verified: false });
    }

    #[test]
    fn todo_ignores_unrelated_actions() {
        let actions = [Action::Verify, Action::Archive, Action::Finish];
        let state = apply_actions(TaskState::Todo, &actions);
        assert_eq!(state, TaskState::Todo);
    }

    #[test]
