        assert_eq!(
            parse_person("id=u1;name=Ada;age=42").unwrap(),
            Person {
                id: "u1".into(),
                name: "Ada".into(),
                age: Some(42),
            }
        );
    }

    #[test]
    fn allows_missing_age() {
        assert_eq!(
            parse_person("name=Lin;id=u2").unwrap(),
            Person {
                id: "u2".into(),
                name: "Lin".into(),
                age: None,
            }
        );
    }

    #[test]
    fn rejects_empty_required_fields() {
        assert!(parse_person("id=;name=Ada").is_err());
