        assert!(parse_person("id=u1;name=Ada;age=200").is_err());
        assert!(parse_person("id=u1;name=Ada;age=abc").is_err());
    }

    #[test]
    fn rejects_malformed_segments() {
        assert!(parse_person("id=u1;broken;name=Ada").is_err());
    }
}

