use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale<'a> {
    pub region: &'a str,
    pub channel: &'a str,
    pub units: u32,
    pub refunded: bool,
}

pub fn sales_report(sales: &[Sale<'_>]) -> Vec<String> {
    let mut grouped: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert((0, 0));
        entry.0 += sale.units;
        entry.1 += 1;
    }

    grouped
        .into_iter()
        .map(|(region, (units, count))| format!("{}: {} units across {} sale(s)", region, units, count))
        .collect()
}

