pub fn extract_scores(lines: &[&str]) -> Vec<(String, u32)> {
    lines
        .iter()
        .filter_map(|line| {
            let (name, score) = line.split_once(':')?;
            let name = name.trim();
            let score = score.trim().parse::<u32>().ok()?;
            if name.is_empty() || score == 0 {
                return None;
            }
            Some((name.to_string(), score))
        })
        .collect()
}

