pub fn render(action: Action) -> String {
    match action {
        Action::View => "view item".to_string(),
        Action::Edit { section } => format!("edit all:{}", section),
        Action::Delete { hard } => {
            if hard {
                "delete soft".to_string()
            } else {
                "delete hard".to_string()
            }
