use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub rep: &'static str,
    pub amount: u32,
    pub refunded: bool,
}

pub fn build_report(rows: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for row in rows {
        let entry = totals.entry(row.region).or_insert((0, 0));
        entry.0 += row.amount;
        if row.refunded {
            entry.1 += 1;
        }
    }

    let mut lines = Vec::new();
    let mut grand_total = 0;
    let mut refund_regions = 0;

    for (region, (amount, refunds)) in totals {
        grand_total += amount;
        refund_regions += refunds;
        lines.push(format!("{}: total={}, refunds={}", region, amount, refunds));
    }

    lines.push(format!(
        "SUMMARY total={}, refund_regions={}",
        grand_total, refund_regions
    ));
    lines.join("\n")
}

