            Sale { region: "west", rep: "bob", amount: 50, refunded: true },
            Sale { region: "east", rep: "cam", amount: 30, refunded: true },
            Sale { region: "north", rep: "dia", amount: 75, refunded: false },
            Sale { region: "west", rep: "eli", amount: 90, refunded: false },
        ];

        let got = build_report(&rows);
        let expected = [
            "east: total=120, refunds=1",
            "north: total=75, refunds=0",
