pub fn collect_tags(input: &[&str]) -> Vec<String> {
    let mut seen = Vec::new();
    input
        .iter()
        .filter_map(|raw| {
            let tag = raw.trim();
            if tag.is_empty() {
                return None;
            }
            let lowered = tag.to_ascii_lowercase();
            let body = lowered.strip_prefix('#').unwrap_or(&lowered);
            if body.is_empty()
                || !body.chars().all(|c| c.is_ascii_alphanumeric() || c == '-')
                || lowered.matches('#').count() > 1
            {
                return None;
            }
            let normalized = format!("#{body}");
            if seen.iter().any(|s| s == &normalized) {
                None
            } else {
                seen.push(normalized.clone());
                Some(normalized)
            }
        })
        .collect()
}

