#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Export,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Resource {
    Document { archived: bool },
    AuditLog,
    Billing,
}

pub fn decide(role: Role, action: Action, resource: Resource) -> &'static str {
    match action {
        Action::View => match resource {
            Resource::Document { archived: true } => "allow",
            Resource::Document { archived: false } => "allow",
            Resource::AuditLog => "allow",
            Resource::Billing => "allow",
        },
        Action::Edit => match resource {
            Resource::Document { archived: true } => "allow",
            Resource::Document { archived: false } => match role {
                Role::Guest => "allow",
                Role::Member => "allow",
                Role::Admin => "allow",
            },
            Resource::AuditLog => "deny",
            Resource::Billing => "deny",
        },
        Action::Delete => match resource {
            Resource::Document { archived: true } => "deny",
            Resource::Document { archived: false } => match role {
                Role::Admin => "allow",
                _ => "deny",
            },
            Resource::AuditLog => "deny",
            Resource::Billing => "deny",
        },
        Action::Export => match resource {
            Resource::Document { archived: true } => "allow",
            Resource::Document { archived: false } => "allow",
            Resource::AuditLog => "deny",
            Resource::Billing => match role {
                Role::Admin => "allow",
                Role::Member => "allow",
                Role::Guest => "allow",
            },
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn view_permissions_match_resource_sensitivity() {
        assert_eq!(decide(Role::Guest, Action::View, Resource::Document { archived: false }), "allow");
        assert_eq!(decide(Role::Member, Action::View, Resource::Document { archived: true }), "allow");
        assert_eq!(decide(Role::Admin, Action::View, Resource::Billing), "allow");
        assert_eq!(decide(Role::Guest, Action::View, Resource::AuditLog), "deny");
        assert_eq!(decide(Role::Member, Action::View, Resource::AuditLog), "allow");
    }

    #[test]
    fn edit_permissions_require_role_and_active_document() {
        assert_eq!(decide(Role::Guest, Action::Edit, Resource::Document { archived: false }), "deny");
        assert_eq!(decide(Role::Member, Action::Edit, Resource::Document { archived: false }), "allow");
        assert_eq!(decide(Role::Admin, Action::Edit, Resource::Document { archived: false }), "allow");
        assert_eq!(decide(Role::Admin, Action::Edit, Resource::Document { archived: true }), "deny");
        assert_eq!(decide(Role::Admin, Action::Edit, Resource::Billing), "deny");
    }

    #[test]
    fn delete_permissions_are_strict() {
        assert_eq!(decide(Role::Admin, Action::Delete, Resource::Document { archived: false }), "allow");
        assert_eq!(decide(Role::Member, Action::Delete, Resource::Document { archived: false }), "deny");
        assert_eq!(decide(Role::Admin, Action::Delete, Resource::Document { archived: true }), "deny");
        assert_eq!(decide(Role::Admin, Action::Delete, Resource::AuditLog), "allow");
    }

    #[test]
    fn export_permissions_vary_by_target() {
