#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u32,
}

#[derive(Debug, Clone, Default)]
pub struct ConfigLayer {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u32>,
}

pub fn merge_config(
    defaults: &Config,
    env: &ConfigLayer,
    profile: Option<&ConfigLayer>,
) -> Config {
    let profile = profile.cloned().unwrap_or_default();

    Config {
        host: profile
            .host
            .or_else(|| env.host.clone())
            .unwrap_or_else(|| defaults.host.clone()),
        port: env.port.or(profile.port).unwrap_or(defaults.port),
        use_tls: profile.use_tls.unwrap_or(env.use_tls.unwrap_or(defaults.use_tls)),
        timeout_ms: profile.timeout_ms.unwrap_or(defaults.timeout_ms),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            host: "localhost".to_string(),
            port: 8080,
            use_tls: false,
            timeout_ms: 1_000,
        }
    }

    #[test]
    fn profile_overrides_env_and_defaults() {
        let env = ConfigLayer {
            host: Some("env.internal".to_string()),
            port: Some(9000),
            use_tls: Some(false),
            timeout_ms: Some(2_500),
        };
        let profile = ConfigLayer {
            host: Some("profile.internal".to_string()),
            port: Some(7000),
            use_tls: Some(true),
            timeout_ms: Some(5_000),
        };

        let merged = merge_config(&defaults(), &env, Some(&profile));

        assert_eq!(
            merged,
            Config {
                host: "profile.internal".to_string(),
                port: 7000,
                use_tls: true,
                timeout_ms: 5_000,
            }
        );
    }

    #[test]
    fn env_fills_only_missing_profile_fields() {
        let env = ConfigLayer {
            host: Some("env.internal".to_string()),
            port: Some(9000),
            use_tls: Some(true),
            timeout_ms: Some(2_500),
        };
        let profile = ConfigLayer {
            host: None,
            port: Some(7000),
            use_tls: None,
            timeout_ms: None,
        };

        let merged = merge_config(&defaults(), &env, Some(&profile));

        assert_eq!(
            merged,
            Config {
                host: "env.internal".to_string(),
                port: 7000,
                use_tls: true,
                timeout_ms: 2_500,
            }
        );
    }

    #[test]
    fn defaults_are_used_when_no_layer_provides_a_value() {
        let env = ConfigLayer::default();
        let merged = merge_config(&defaults(), &env, None);

        assert_eq!(
            merged,
            Config {
                host: "localhost".to_string(),
                port: 8080,
                use_tls: false,
                timeout_ms: 1_000,
            }
        );
    }

    #[test]
    fn explicit_false_in_profile_must_override_true_from_env() {
        let env = ConfigLayer {
            host: None,
            port: None,
            use_tls: Some(true),
            timeout_ms: None,
        };
        let profile = ConfigLayer {
            host: None,
