}

use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Status {
    Pending,
    Shipped,
    Cancelled,
}

#[derive(Clone, Debug)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: u32,
    pub status: Status,
}

pub fn build_region_report(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for order in orders {
        let entry = totals.entry(order.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += order.amount_cents;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(region, (count, cents))| format!("{}|{}|{}", region, count, cents))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn reports_only_shipped_orders_and_sorts_by_revenue_desc_then_region() {
        let orders = [
            Order { region: "west", amount_cents: 400, status: Status::Shipped },
            Order { region: "east", amount_cents: 250, status: Status::Pending },
            Order { region: "north", amount_cents: 500, status: Status::Shipped },
            Order { region: "west", amount_cents: 150, status: Status::Cancelled },
            Order { region: "east", amount_cents: 500, status: Status::Shipped },
            Order { region: "west", amount_cents: 200, status: Status::Shipped },
        ];

        let report = build_region_report(&orders);
        assert_eq!(report, "east|1|500\nnorth|1|500\nwest|2|600");
    }

    #[test]
    fn omits_regions_without_shipped_orders() {
        let orders = [
            Order { region: "south", amount_cents: 800, status: Status::Pending },
            Order { region: "south", amount_cents: 100, status: Status::Cancelled },
            Order { region: "mid", amount_cents: 300, status: Status::Shipped },
        ];

        let report = build_region_report(&orders);
        assert_eq!(report, "mid|1|300");
    }

    #[test]
    fn empty_when_nothing_shipped() {
        let orders = [
            Order { region: "west", amount_cents: 100, status: Status::Pending },
            Order { region: "east", amount_cents: 200, status: Status::Cancelled },
        ];

        assert_eq!(build_region_report(&orders), "");
    }
}

