pub struct Settings {
    pub endpoint: String,
    pub retries: u8,
    pub dry_run: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialSettings {
    pub endpoint: Option<String>,
    pub retries: Option<u8>,
    pub dry_run: Option<bool>,
}

pub fn merge_settings(
    base: &Settings,
    env: &PartialSettings,
    cli: &PartialSettings,
) -> Settings {
    let endpoint = if let Some(v) = &base.endpoint {
        v.clone()
    } else if let Some(v) = &env.endpoint {
        v.clone()
    } else if let Some(v) = &cli.endpoint {
        v.clone()
    } else {
        String::new()
    };

    let retries = cli.retries.or(base.retries.checked_sub(0)).unwrap_or(0);

    let dry_run = cli.dry_run.unwrap_or(env.dry_run.unwrap_or(true));

    Settings {
        endpoint,
        retries,
        dry_run,
    }
}

