use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub user: String,
    pub points: u32,
    pub wins: u32,
    pub last_submission: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub user: String,
    pub points: u32,
    pub wins: u32,
    pub last_submission: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut merged: BTreeMap<String, Entry> = BTreeMap::new();

    for e in entries {
        merged
            .entry(e.user.clone())
            .and_modify(|cur| {
                cur.points += e.points;
                cur.wins += e.wins;
                if e.last_submission > cur.last_submission {
                    cur.last_submission = e.last_submission;
                }
            })
            .or_insert_with(|| e.clone());
    }

    let mut rows: Vec<Entry> = merged.into_values().collect();
    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.last_submission.cmp(&b.last_submission))
            .then(a.user.cmp(&b.user))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, e)| RankedEntry {
            rank: i + 1,
            user: e.user,
            points: e.points,
            wins: e.wins,
            last_submission: e.last_submission,
        })
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn names(rows: &[RankedEntry]) -> Vec<&str> {
        rows.iter().map(|r| r.user.as_str()).collect()
    }

    #[test]
    fn sorts_by_points_then_wins_then_earlier_submission_then_name() {
        let rows = leaderboard(&[
            Entry { user: "zoe".into(), points: 12, wins: 3, last_submission: 50 },
            Entry { user: "amy".into(), points: 12, wins: 3, last_submission: 40 },
            Entry { user: "bob".into(), points: 15, wins: 1, last_submission: 99 },
            Entry { user: "cyd".into(), points: 12, wins: 4, last_submission: 70 },
            Entry { user: "ann".into(), points: 12, wins: 3, last_submission: 40 },
        ]);

        assert_eq!(names(&rows), vec!["bob", "cyd", "amy", "ann", "zoe"]);
    }

    #[test]
    fn duplicate_users_are_merged_with_sum_sum_and_earliest_submission() {
        let rows = leaderboard(&[
            Entry { user: "ivy".into(), points: 7, wins: 1, last_submission: 80 },
            Entry { user: "max".into(), points: 5, wins: 5, last_submission: 20 },
            Entry { user: "ivy".into(), points: 8, wins: 2, last_submission: 30 },
        ]);

        assert_eq!(rows[0].user, "ivy");
        assert_eq!(rows[0].points, 15);
        assert_eq!(rows[0].wins, 3);
        assert_eq!(rows[0].last_submission, 30);
    }

    #[test]
    fn equal_scores_share_rank_and_next_rank_skips_positions() {
        let rows = leaderboard(&[
            Entry { user: "amy".into(), points: 10, wins: 2, last_submission: 20 },
            Entry { user: "bob".into(), points: 10, wins: 2, last_submission: 20 },
            Entry { user: "cyd".into(), points: 9, wins: 9, last_submission: 1 },
