        .cmp(&a.points)
        .then(a.wins.cmp(&b.wins))
        .then(a.last_submission.cmp(&b.last_submission))
        .then(a.user.cmp(&b.user))
});

if e.last_submission < cur.last_submission {
    cur.last_submission = e.last_submission;
}

let mut out = Vec::with_capacity(rows.len());
let mut prev: Option<(u32, u32, u32)> = None;
let mut rank = 0;

for (i, e) in rows.into_iter().enumerate() {
    let key = (e.points, e.wins, e.last_submission);
    if prev.as_ref() != Some(&key) {
        rank = i + 1;
        prev = Some(key);
    }
    out.push(RankedEntry {
        rank,
        user: e.user,
        points: e.points,
        wins: e.wins,
        last_submission: e.last_submission,
    });
}

out

