pub fn has_conflict(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    let (start, end) = candidate;
    if start >= end {
        return true;
    }

    existing.iter().any(|&(s, e)| {
        start <= e && end >= s
    })
}

#[cfg(test)]
mod tests {
    use super::has_conflict;

    #[test]
    fn allows_adjacent_booking() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(!has_conflict(&existing, (20, 30)));
        assert!(!has_conflict(&existing, (0, 10)));
        assert!(!has_conflict(&existing, (40, 50)));
    }

    #[test]
    fn rejects_partial_overlap() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(has_conflict(&existing, (15, 25)));
        assert!(has_conflict(&existing, (25, 35)));
    }

    #[test]
    fn rejects_containment_cases() {
        let existing = vec![(10, 20), (30, 40)];
        assert!(has_conflict(&existing, (12, 18)));
        assert!(has_conflict(&existing, (5, 45)));
    }

    #[test]
    fn rejects_invalid_candidate_range() {
        let existing = vec![(10, 20)];
        assert!(has_conflict(&existing, (7, 7)));
        assert!(has_conflict(&existing, (9, 8)));
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub goals_for: i32,
    pub goals_against: i32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub points: i32,
    pub goal_diff: i32,
    pub played: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut rows: Vec<RankedPlayer> = players
        .iter()
        .enumerate()
        .map(|(idx, p)| RankedPlayer {
            rank: idx + 1,
            name: p.name,
            points: (p.wins as i32) * 2 + p.draws as i32,
            goal_diff: p.goals_for - p.goals_against,
            played: p.wins + p.draws + p.losses,
        })
        .collect();

    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.goal_diff.cmp(&b.goal_diff))
            .then(a.played.cmp(&b.played))
            .then(a.name.cmp(&b.name))
    });

    for (idx, row) in rows.iter_mut().enumerate() {
        row.rank = idx + 1;
    }

    rows
}

#[cfg(test)]
mod tests {
    use super::*;

