        let players = vec![
            Player { name: "Comets", wins: 4, draws: 1, losses: 0, goals_for: 9, goals_against: 3 },
            Player { name: "Bruins", wins: 4, draws: 1, losses: 0, goals_for: 8, goals_against: 2 },
            Player { name: "Arrows", wins: 4, draws: 1, losses: 0, goals_for: 7, goals_against: 1 },
            Player { name: "Dynamos", wins: 3, draws: 0, losses: 2, goals_for: 6, goals_against: 5 },
        ];

        let ranked = rank_players(&players);
        let names: Vec<_> = ranked.iter().map(|r| r.name).collect();
        assert_eq!(names, vec!["Arrows", "Bruins", "Comets", "Dynamos"]);
        let ranks: Vec<_> = ranked.iter().map(|r| r.rank).collect();
        assert_eq!(ranks, vec![1, 2, 3, 4]);
    }

    #[test]
    fn fewer_matches_played_wins_tie_break_after_goal_diff() {
        let players = vec![
            Player { name: "Falcons", wins: 3, draws: 3, losses: 0, goals_for: 9, goals_against: 6 },
            Player { name: "Eagles", wins: 4, draws: 1, losses: 0, goals_for: 8, goals_against: 5 },
            Player { name: "Giants", wins: 2, draws: 0, losses: 3, goals_for: 4, goals_against: 7 },
        ];

        let ranked = rank_players(&players);
        let names: Vec<_> = ranked.iter().map(|r| r.name).collect();
        assert_eq!(names, vec!["Eagles", "Falcons", "Giants"]);
    }

    #[test]
    fn standard_scoring_and_competition_ranks_are_used() {
        let players = vec![
            Player { name: "Ajax", wins: 2, draws: 1, losses: 0, goals_for: 5, goals_against: 2 },
            Player { name: "Blaze", wins: 2, draws: 1, losses: 0, goals_for: 5, goals_against: 2 },
            Player { name: "Cyclones", wins: 1, draws: 3, losses: 0, goals_for: 4, goals_against: 3 },
            Player { name: "Dragons", wins: 1, draws: 0, losses: 3, goals_for: 2, goals_against: 8 },
        ];

        let ranked = rank_players(&players);
        let summary: Vec<_> = ranked
