                ("Cyclones", 3, 6, 1),
                ("Dragons", 4, 3, -6),
            ]
        );
    }

    #[test]
    fn empty_input_returns_empty_output() {
        let ranked = rank_players(&[]);
        assert!(ranked.is_empty());
    }
}

