#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Channel {
    Email,
    Sms,
    Push,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Audience {
    Active,
    Inactive,
    Trial,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Signup,
    Purchase { amount_cents: u32 },
    Renewal { overdue_days: u16 },
    Bounce { hard: bool },
}

pub fn action_for(event: Event, channel: Channel, audience: Audience) -> &'static str {
    match event {
        Event::Signup => match channel {
            Channel::Email => "welcome_email",
            Channel::Sms => "welcome_sms",
            Channel::Push => "welcome_push",
        },
        Event::Purchase { amount_cents } => {
            if amount_cents >= 10_000 {
                "vip_offer"
            } else {
                match audience {
                    Audience::Inactive => "winback_discount",
                    _ => "receipt",
                }
            }
        }
        Event::Renewal { overdue_days } => {
            if overdue_days == 0 {
                "renewal_thanks"
            } else if overdue_days < 7 {
                "gentle_reminder"
            } else {
                "gentle_reminder"
            }
        }
        Event::Bounce { hard } => {
            if hard {
                "retry_later"
            } else {
                "suppress_contact"
            }
        }
    }
}

