        assert_eq!(action_for(Event::Signup, Channel::Email, Audience::Active), "welcome_email");
        assert_eq!(action_for(Event::Signup, Channel::Sms, Audience::Trial), "welcome_sms");
        assert_eq!(action_for(Event::Signup, Channel::Push, Audience::Inactive), "welcome_push");
    }

