#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub active: bool,
    pub score: u8,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (idx, line) in input.lines().enumerate() {
        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", idx + 1));
        }

        let name = parts[0].trim();
        if name.is_empty() {
            return Err(format!("line {}: empty name", idx + 1));
        }

        let active = match parts[1].trim() {
            "active" => true,
            "inactive" => false,
            _ => return Err(format!("line {}: invalid status", idx + 1)),
        };

        let score: u8 = parts[2]
            .trim()
            .parse()
            .map_err(|_| format!("line {}: invalid score", idx + 1))?;

        out.push(Record {
            name: name.to_string(),
            active,
            score,
        });
    }
    Ok(out)
}

