        let input = "Alice|active|42\nBob|inactive|0\nCara|active|100";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record { name: "Alice".into(), active: true, score: 42 },
                Record { name: "Bob".into(), active: false, score: 0 },
                Record { name: "Cara".into(), active: true, score: 100 },
            ]
        );
    }

    #[test]
    fn ignores_blank_lines_between_records() {
        let input = "Alice|active|42\n\nBob|inactive|7\n   \nCara|active|100";
        let got = parse_records(input).unwrap();
        assert_eq!(got.len(), 3);
        assert_eq!(got[1], Record { name: "Bob".into(), active: false, score: 7 });
    }

    #[test]
    fn rejects_score_with_surrounding_spaces() {
        let err = parse_records("Alice|active| 7").unwrap_err();
        assert_eq!(err, "line 1: invalid score");
    }

    #[test]
    fn rejects_out_of_range_score() {
        let err = parse_records("Alice|active|101").unwrap_err();
        assert_eq!(err, "line 1: invalid score");
    }

    #[test]
    fn rejects_invalid_status_and_empty_name() {
        let err = parse_records(" |active|5").unwrap_err();
        assert_eq!(err, "line 1: empty name");

        let err = parse_records("Alice|paused|5").unwrap_err();
        assert_eq!(err, "line 1: invalid status");
    }
