use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: &'static str,
    pub person: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn build_team_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for entry in entries {
        let bucket = totals.entry(entry.team).or_insert((0, 0));
        bucket.0 += 1;
        if entry.billable {
            bucket.1 += 1;
        }
    }

    let mut lines = Vec::new();
    for (team, (hours, billable_hours)) in totals {
        lines.push(format!("{}: total={} billable={}", team, hours, billable_hours));
    }

    if lines.is_empty() {
        "no teams".to_string()
    } else {
        lines.join("\n")
    }
}

