#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Channel {
    Email,
    Sms,
    Push,
    Webhook,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Priority {
    Low,
    Normal,
    High,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Welcome,
    PasswordReset,
    BillingFailure,
    WeeklyDigest,
}

pub fn delivery_action(channel: Channel, priority: Priority, event: Event) -> &'static str {
    match channel {
        Channel::Email => match event {
            Event::Welcome => "queue_email",
            Event::PasswordReset => "queue_email",
            Event::BillingFailure => "drop",
            Event::WeeklyDigest => "send_immediately",
        },
        Channel::Sms => match event {
            Event::Welcome => "drop",
            Event::PasswordReset => "queue_email",
            Event::BillingFailure => "send_immediately",
            Event::WeeklyDigest => "drop",
        },
        Channel::Push => match priority {
            Priority::High => "send_immediately",
            Priority::Normal => "drop",
            Priority::Low => "queue_email",
        },
        Channel::Webhook => match event {
            Event::Welcome => "send_immediately",
            Event::PasswordReset => "send_immediately",
            Event::BillingFailure => "queue_email",
            Event::WeeklyDigest => "send_immediately",
        },
    }
}

