#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Todo,
    InProgress,
    Done,
    Archived,
}

pub fn apply_event(status: Status, event: &str) -> Status {
    match (status, event) {
        (Status::Todo, "start") => Status::InProgress,
        (_, "finish") => Status::Done,
        (Status::Done, "archive") => Status::Archived,
        (_, "reset") => Status::Todo,
        _ => status,
    }
}

