}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub timeout_ms: Option<u32>,
    pub retries: Option<u8>,
}

pub fn merge_config(defaults: &Config, env: &PartialConfig, cli: &PartialConfig) -> Config {
    Config {
        host: cli
            .host
            .clone()
            .or_else(|| env.host.clone())
            .unwrap_or_else(|| defaults.host.clone()),
        port: cli.port.or(env.port).unwrap_or(defaults.port),
        tls: cli.tls.or(env.tls).unwrap_or(defaults.tls),
        timeout_ms: env.timeout_ms.or(cli.timeout_ms).unwrap_or(defaults.timeout_ms),
        retries: cli.retries.unwrap_or(defaults.retries),
    }
}

