#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub qty: u32,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let parts: Vec<_> = line.split('|').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", line_no));
        }

        let name = parts[0].trim();
        if name.is_empty() {
            return Err(format!("line {}: empty name", line_no));
        }

        let qty: u32 = parts[1]
            .trim()
            .parse()
            .map_err(|_| format!("line {}: invalid qty", line_no))?;

        let tags: Vec<String> = if parts[2].trim().is_empty() {
            Vec::new()
        } else {
            parts[2]
                .split(',')
                .map(|t| t.trim().to_string())
                .collect()
        };

        if tags.is_empty() {
            return Err(format!("line {}: at least one tag required", line_no));
        }

        out.push(Record {
            name: name.to_string(),
            qty,
            tags,
        });
    }

    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_records_with_comments_and_blank_lines() {
        let input = "\n# inventory\napple|10|fresh,food\n\npear|2|green\n";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    name: "apple".into(),
                    qty: 10,
                    tags: vec!["fresh".into(), "food".into()],
                },
                Record {
                    name: "pear".into(),
                    qty: 2,
                    tags: vec!["green".into()],
                }
            ]
        );
    }

    #[test]
    fn rejects_zero_qty() {
        let err = parse_records("apple|0|fresh").unwrap_err();
        assert_eq!(err, "line 1: qty must be > 0");
    }

    #[test]
    fn rejects_empty_or_duplicate_tags_after_trimming() {
        let err = parse_records("apple|3|fresh, ,fresh").unwrap_err();
        assert_eq!(err, "line 1: duplicate tag 'fresh'");
    }

    #[test]
    fn rejects_empty_tag_even_without_duplicates() {
        let err = parse_records("apple|3|fresh,").unwrap_err();
        assert_eq!(err, "line 1: empty tag");
    }
}

