use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
    pub goal_diff: i32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut players = players.to_vec();
    players.sort_by(|a, b| {
        a.points.cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.goal_diff.cmp(&b.goal_diff))
            .then_with(|| a.name.cmp(b.name))
    });

    players
        .into_iter()
        .enumerate()
        .map(|(idx, p)| format!("{}. {} ({} pts, {} wins, gd {})", idx + 1, p.name, p.points, p.wins, p.goal_diff))
        .collect()
}

