    #[test]
    fn groups_sorted_and_uses_billable_hours_only() {
        let events = [
            Event { team: "ops", hours: 3, billable: false },
            Event { team: "api", hours: 2, billable: true },
            Event { team: "ops", hours: 5, billable: true },
            Event { team: "api", hours: 4, billable: false },
            Event { team: "web", hours: 1, billable: true },
        ];

        let got = build_report(&events);
        let expected = "api: 2h billable across 2 events\nops: 5h billable across 2 events\nweb: 1h billable across 1 event\nTOTAL: 8h billable across 3 billable events";
        assert_eq!(got, expected);
    }

    #[test]
    fn skips_teams_with_no_billable_work_but_keeps_total_line() {
        let events = [
            Event { team: "ops", hours: 2, billable: false },
            Event { team: "ops", hours: 1, billable: false },
            Event { team: "api", hours: 4, billable: true },
        ];

        let got = build_report(&events);
        let expected = "api: 4h billable across 1 event\nTOTAL: 4h billable across 1 billable event";
        assert_eq!(got, expected);
    }

    #[test]
    fn empty_input_reports_zero_total() {
        let got = build_report(&[]);
        assert_eq!(got, "TOTAL: 0h billable across 0 billable events");
    }
}

