#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum OrderState {
    Draft,
    Submitted,
    Approved,
    Shipped,
    Cancelled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Ship,
    Cancel,
}

pub fn apply_event(state: OrderState, event: Event) -> OrderState {
    match (state, event) {
        (OrderState::Draft, Event::Submit) => OrderState::Submitted,
        (OrderState::Submitted, Event::Approve) => OrderState::Approved,
        (OrderState::Approved, Event::Ship) => OrderState::Shipped,
        (_, Event::Cancel) => OrderState::Cancelled,
        _ => state,
    }
}

