pub fn has_conflict(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    let (start, end) = candidate;
    if start >= end {
        return true;
    }

    existing.iter().any(|&(s, e)| start <= e && s <= end)
}

