    fn closed_from_draft_cannot_reopen() {
        let events = [Event::Close, Event::Reopen];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn resume_only_works_when_suspended() {
        let events = [Event::Submit, Event::Resume, Event::Suspend, Event::Resume];
        assert_eq!(apply_events(&events), Status::Active);
    }

