    fn submit_after_reopen_from_closed_returns_to_active() {
        let events = [Event::Submit, Event::Close, Event::Reopen, Event::Submit];
        assert_eq!(apply_events(&events), Status::Active);
    }

    #[test]
    fn suspend_then_reopen_without_close_does_nothing() {
        let events = [Event::Submit, Event::Suspend, Event::Reopen];
        assert_eq!(apply_events(&events), Status::Suspended);
    }
}

