}

pub fn merge_config(defaults: &Config, file: Option<&PartialConfig>, env: Option<&PartialConfig>) -> Config {
    let mut merged = defaults.clone();

    if let Some(file_cfg) = file {
        if let Some(host) = &file_cfg.host {
            merged.host = host.clone();
        }
        if let Some(port) = file_cfg.port {
            merged.port = port;
        }
        if let Some(use_tls) = file_cfg.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = file_cfg.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
    }

    if let Some(env_cfg) = env {
        if let Some(port) = env_cfg.port {
            merged.port = port;
        }
        if let Some(use_tls) = env_cfg.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(timeout_ms) = env_cfg.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
        if let Some(host) = &env_cfg.host {
            if !host.is_empty() {
                merged.host = defaults.host.clone();
            }
        }
    }

    if merged.use_tls {
        merged.port = 443;
    }

    merged
}

