#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Booking {
    pub room: String,
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(room: &str, start: u32, end: u32) -> Self {
        Self {
            room: room.to_string(),
            start,
            end,
        }
    }
}

pub fn can_book(existing: &[Booking], room: &str, start: u32, end: u32) -> bool {
    if start > end {
        return true;
    }

    for booking in existing {
        if booking.room != room {
            continue;
        }

        if overlaps(booking.start, booking.end, start, end) {
            return false;
        }
    }

    true
}

fn overlaps(a_start: u32, a_end: u32, b_start: u32, b_end: u32) -> bool {
    a_start <= b_end && b_start <= a_end
}

#[cfg(test)]
mod tests {
    use super::*;

    fn b(room: &str, start: u32, end: u32) -> Booking {
        Booking::new(room, start, end)
    }

    #[test]
    fn rejects_invalid_or_zero_length_requests() {
        let existing = [b("A", 10, 20)];
        assert!(!can_book(&existing, "A", 15, 15));
        assert!(!can_book(&existing, "A", 21, 20));
    }

    #[test]
    fn touching_edges_do_not_conflict_in_same_room() {
        let existing = [b("A", 10, 20), b("A", 30, 40)];
        assert!(can_book(&existing, "A", 20, 30));
        assert!(can_book(&existing, "A", 0, 10));
        assert!(can_book(&existing, "A", 40, 50));
    }

    #[test]
    fn real_overlap_inside_same_room_is_rejected() {
