use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: u32,
    pub ok: bool,
}

pub fn monthly_region_report(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for order in orders {
        let entry = totals.entry(order.region).or_insert((0, 0));
        entry.0 += order.amount_cents;
        entry.1 += 1;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::from("region | orders | revenue\n");
    let mut grand = 0u32;

    for (region, (revenue, count)) in rows {
        grand += revenue;
        out.push_str(&format!("{} | {} | {}\n", region, revenue, count));
    }

    out.push_str(&format!("TOTAL | {}\n", grand));
    out
}

#[cfg(test)]
