            Order { region: "east", amount_cents: 1200, ok: true },
            Order { region: "west", amount_cents: 200, ok: true },
            Order { region: "north", amount_cents: 900, ok: false },
            Order { region: "east", amount_cents: 300, ok: true },
            Order { region: "south", amount_cents: 800, ok: true },
        ];

        let expected = concat!(
            "region | orders | revenue\n",
            "east | 2 | 1500\n",
            "south | 1 | 800\n",
            "west | 2 | 700\n",
