            Order { region: "beta", amount_cents: 300, ok: true },
            Order { region: "alpha", amount_cents: 600, ok: false },
            Order { region: "gamma", amount_cents: 100, ok: true },
            Order { region: "gamma", amount_cents: 400, ok: true },
