#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;

    for event in events {
        status = match (status, event) {
            (Status::New, Event::Start) => Status::InProgress,
            (Status::InProgress, Event::Block) => Status::Blocked,
            (Status::Blocked, Event::Unblock) => Status::InProgress,
            (_, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::InProgress,
            (_, _) => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn full_lifecycle_can_close() {
        let events = [Start, Resolve, Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn cannot_resolve_before_work_starts() {
        let events = [Resolve];
        assert_eq!(apply_events(&events), Status::New);
    }

    #[test]
    fn blocked_ticket_must_be_unblocked_before_resolve() {
        let events = [Start, Block, Resolve];
        assert_eq!(apply_events(&events), Status::Blocked);
    }

    #[test]
    fn reopen_from_closed_requires_new_start() {
        let events = [Start, Resolve, Close, Reopen];
        assert_eq!(apply_events(&events), Status::New);
    }

    #[test]
    fn close_is_ignored_unless_resolved() {
        let events = [Start, Close];
        assert_eq!(apply_events(&events), Status::InProgress);
    }
}

