use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub points: u32,
    pub wins: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut best_by_name: HashMap<&str, &Player> = HashMap::new();
    for player in players {
        best_by_name.insert(&player.name, player);
    }

    let mut ranked: Vec<&Player> = best_by_name.into_values().collect();
    ranked.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.name.cmp(&b.name))
    });

    ranked.into_iter().map(|p| p.name.clone()).collect()
}

