use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn summarize_sales(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut months: BTreeMap<&str, u8> = BTreeMap::new();

    for sale in sales {
        if sale.month < 1 || sale.month > 12 {
            continue;
        }
        let entry = totals.entry(sale.region).or_insert(0);
        *entry += sale.amount;

        let month_entry = months.entry(sale.region).or_insert(0);
        *month_entry += 1;
    }

    let mut out = Vec::new();
    for (region, total) in totals {
        let count = months.get(region).copied().unwrap_or(0);
        out.push(format!("{}: total={}, months={}", region, total, count));
    }
    out.join("\n")
}

