#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TicketState {
    New,
    InProgress,
    Blocked,
    Done,
    Canceled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Resume,
    Complete,
    Cancel,
}

pub fn apply_events(events: &[Event]) -> TicketState {
    let mut state = TicketState::New;
    for event in events {
        state = match (state, event) {
            (TicketState::New, Event::Start) => TicketState::InProgress,
            (_, Event::Block) => TicketState::Blocked,
            (TicketState::Blocked, Event::Resume) => TicketState::InProgress,
            (_, Event::Complete) => TicketState::Done,
            (_, Event::Cancel) => TicketState::Canceled,
            _ => state,
        };
    }
    state
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, TicketState};

    #[test]
    fn complete_requires_progress() {
        assert_eq!(apply_events(&[Event::Complete]), TicketState::New);
        assert_eq!(apply_events(&[Event::Start, Event::Complete]), TicketState::Done);
    }

    #[test]
    fn block_only_from_in_progress_and_resume_only_from_blocked() {
        assert_eq!(apply_events(&[Event::Block]), TicketState::New);
        assert_eq!(apply_events(&[Event::Start, Event::Block]), TicketState::Blocked);
        assert_eq!(apply_events(&[Event::Resume]), TicketState::New);
        assert_eq!(apply_events(&[Event::Start, Event::Resume]), TicketState::InProgress);
    }

    #[test]
    fn terminal_states_ignore_future_events() {
        assert_eq!(apply_events(&[Event::Start, Event::Complete, Event::Block]), TicketState::Done);
        assert_eq!(apply_events(&[Event::Cancel, Event::Start, Event::Complete]), TicketState::Canceled);
    }

    #[test]
    fn cancel_from_done_is_ignored() {
        assert_eq!(apply_events(&[Event::Start, Event::Complete, Event::Cancel]), TicketState::Done);
        assert_eq!(apply_events(&[Event::Start, Event::Cancel]), TicketState::Canceled);
    }
}

#[derive(Debug, PartialEq, Eq)]
pub struct Metrics {
    pub ids: Vec<String>,
    pub total_score: i32,
    pub flagged_count: usize,
}

pub fn collect_metrics(lines: &[&str]) -> Metrics {
    let parsed: Vec<(&str, i32, bool)> = lines
        .iter()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let id = parts.next()?;
            let score = parts.next()?.parse::<i32>().ok()?;
            let status = parts.next()?;
            Some((id, score, status == "flag"))
        })
        .collect();

    let ids = parsed
        .iter()
        .filter(|(_, score, _)| *score >= 0)
        .map(|(id, _, _)| id.to_string())
        .collect();

    let total_score = parsed
        .iter()
        .filter(|(_, score, _)| *score >= 0)
        .map(|(_, score, _)| *score)
        .sum();

    let flagged_count = parsed.iter().filter(|(_, _, flagged)| *flagged).count();

    Metrics {
        ids,
        total_score,
        flagged_count,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn skips_bad_rows_and_trims_accepts_ok_or_flag() {
        let lines = [
            " alpha | 10 | ok ",
            "beta|-3|flag",
            "gamma|7|hold",
            " |5|ok",
            "delta|bogus|flag",
            "epsilon|9|flag|extra",
            "zeta|4|ok",
        ];

        let got = collect_metrics(&lines);
        assert_eq!(
            got,
            Metrics {
                ids: vec!["alpha".into(), "beta".into(), "zeta".into()],
                total_score: 11,
                flagged_count: 1,
            }
        );
    }

    #[test]
    fn keeps_input_order_allows_negative_scores_and_counts_only_included_flags() {
        let lines = [
            "id3|2|flag",
            "id1|-2|ok",
            "id2|0|flag",
            "id4|5|skip",
            "id5|1|ok",
        ];

        let got = collect_metrics(&lines);
        assert_eq!(got.ids, vec!["id3", "id1", "id2", "id5"]);
        assert_eq!(got.total_score, 1);
        assert_eq!(got.flagged_count, 2);
    }

    #[test]
    fn ignores_rows_with_missing_fields_or_blank_status() {
        let lines = [
            "a|1",
            "b|2|",
            "c|3|ok",
            "d|4|flag",
            "e|5|ok|tail",
        ];

        let got = collect_metrics(&lines);
        assert_eq!(got.ids, vec!["c", "d"]);
        assert_eq!(got.total_score, 7);
        assert_eq!(got.flagged_count, 1);
    }
}

