#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Method {
    Get,
    Post,
    Delete,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Target {
    Collection,
    Item(u64),
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    List,
    Create,
    Fetch(u64),
    Remove(u64),
    Reject(&'static str),
}

pub fn route(method: Method, target: Target, authenticated: bool) -> Action {
    match (method, target, authenticated) {
        (Method::Get, Target::Collection, _) => Action::Fetch(0),
        (Method::Post, Target::Collection, false) => Action::Create,
        (Method::Get, Target::Item(id), _) => Action::Fetch(id),
        (Method::Delete, Target::Item(id), _) => Action::Reject("forbidden"),
        (Method::Delete, Target::Collection, _) => Action::Remove(0),
        _ => Action::Reject("not_found"),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn collection_routes_are_distinct() {
        assert_eq!(route(Method::Get, Target::Collection, false), Action::List);
        assert_eq!(route(Method::Post, Target::Collection, true), Action::Create);
        assert_eq!(
            route(Method::Post, Target::Collection, false),
            Action::Reject("forbidden")
        );
    }

    #[test]
    fn item_routes_handle_ids_and_auth() {
        assert_eq!(route(Method::Get, Target::Item(7), false), Action::Fetch(7));
        assert_eq!(route(Method::Delete, Target::Item(7), true), Action::Remove(7));
        assert_eq!(
            route(Method::Delete, Target::Item(7), false),
            Action::Reject("forbidden")
        );
    }

    #[test]
    fn unsupported_routes_are_not_found() {
        assert_eq!(
            route(Method::Delete, Target::Collection, true),
            Action::Reject("not_found")
        );
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking, cleaning_gap: u32) -> bool {
    if candidate.start > candidate.end {
        return false;
    }

    for b in existing {
        let buffered_end = b.end + cleaning_gap;
        if candidate.start <= buffered_end && candidate.end >= b.start {
            return false;
        }
    }

    true
}

pub fn insert_booking(existing: &mut Vec<Booking>, candidate: Booking, cleaning_gap: u32) -> bool {
    if can_book(existing, candidate, cleaning_gap) {
        existing.push(candidate);
        existing.sort_by_key(|b| b.start);
        true
    } else {
        false
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn rejects_zero_length_and_reversed_ranges() {
        let existing = vec![Booking::new(10, 12)];
        assert!(!can_book(&existing, Booking::new(5, 5), 0));
        assert!(!can_book(&existing, Booking::new(9, 7), 0));
    }

    #[test]
    fn touching_without_gap_is_allowed_for_half_open_ranges() {
        let existing = vec![Booking::new(10, 12)];
        assert!(can_book(&existing, Booking::new(12, 15), 0));
        assert!(can_book(&existing, Booking::new(7, 10), 0));
    }

    #[test]
    fn cleaning_gap_blocks_exact_touch_after_existing_end() {
        let existing = vec![Booking::new(10, 12)];
        assert!(!can_book(&existing, Booking::new(12, 14), 1));
        assert!(can_book(&existing, Booking::new(13, 14), 1));
    }

    #[test]
    fn candidate_must_not_cover_existing_even_if_it_starts_before_it() {
        let existing = vec![Booking::new(10, 12)];
        assert!(!can_book(&existing, Booking::new(8, 13), 0));
    }

    #[test]
    fn insert_keeps_start_order_when_booking_is_valid() {
        let mut existing = vec![Booking::new(20, 22), Booking::new(5, 7)];
        assert!(insert_booking(&mut existing, Booking::new(12, 14), 0));
        assert_eq!(existing, vec![Booking::new(5, 7), Booking::new(12, 14), Booking::new(20, 22)]);
    }
}

