use std::collections::BTreeMap;

#[derive(Clone, Debug)]
pub struct Entry {
    pub team: &'static str,
    pub category: &'static str,
    pub hours: u32,
    pub billable: bool,
}

#[derive(Debug, PartialEq, Eq)]
pub struct TeamSummary {
    pub team: String,
    pub total_hours: u32,
    pub billable_hours: u32,
    pub categories: Vec<String>,
}

pub fn build_report(entries: &[Entry], min_total_hours: u32) -> Vec<TeamSummary> {
    let mut grouped: BTreeMap<&str, TeamSummary> = BTreeMap::new();

    for entry in entries {
        let summary = grouped.entry(entry.team).or_insert_with(|| TeamSummary {
            team: entry.team.to_string(),
            total_hours: 0,
            billable_hours: 0,
            categories: Vec::new(),
        });

        summary.total_hours += entry.hours;
        if entry.billable {
            summary.billable_hours += entry.hours;
        }
        summary.categories.push(entry.category.to_string());
    }

    let mut summaries: Vec<TeamSummary> = grouped
        .into_values()
        .filter(|s| s.total_hours > min_total_hours)
        .collect();

    summaries.sort_by(|a, b| a.team.cmp(&b.team));
    summaries
}

