#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

pub fn rank_names(entries: &[Entry]) -> Vec<String> {
    let mut best_by_name: HashMap<String, Entry> = HashMap::new();

    for entry in entries {
        match best_by_name.get(&entry.name) {
            Some(existing) => {
                if entry.score > existing.score {
                    best_by_name.insert(entry.name.clone(), entry.clone());
                }
            }
            None => {
                best_by_name.insert(entry.name.clone(), entry.clone());
            }
        }
    }

    let mut ranked: Vec<Entry> = best_by_name.into_values().collect();
    ranked.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.penalties.cmp(&b.penalties))
            .then(a.name.cmp(&b.name))
    });

    ranked.into_iter().map(|e| e.name).collect()
}

