pub fn collect_tags(input: &[&str]) -> Vec<String> {
    let mut out = Vec::new();

    for raw in input.iter() {
        if raw.is_empty() || raw.starts_with('#') {
            continue;
        }

        let tag = raw.to_lowercase();
        if !out.contains(&tag) {
            out.push(tag);
