    Closed,
}

#[derive(Debug, Clone, Copy)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = match (status, event) {
            (Status::New, Event::Start) => Status::InProgress,
            (Status::InProgress, Event::Block) => Status::Blocked,
            (Status::Blocked, Event::Unblock) => Status::New,
            (Status::InProgress, Event::Complete) => Status::Closed,
            (Status::Done, Event::Close) => Status::Done,
            (Status::Closed, Event::Reopen) => Status::Done,
            (_, Event::Close) => Status::Closed,
            _ => status,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn happy_path_reaches_closed() {
        let events = [Event::Start, Event::Complete, Event::Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn unblock_returns_to_in_progress() {
        let events = [Event::Start, Event::Block, Event::Unblock];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn close_only_allowed_from_done() {
        let events = [Event::Close];
        assert_eq!(apply_events(&events), Status::New);
    }

    #[test]
    fn reopen_closed_ticket_goes_back_to_in_progress() {
        let events = [Event::Start, Event::Complete, Event::Close, Event::Reopen];
        assert_eq!(apply_events(&events), Status::InProgress);
    }
}

pub fn collect_codes(input: &str) -> Vec<String> {
    input
        .lines()
        .filter_map(|line| {
            let line = line.trim();
            if line.is_empty() || line.starts_with('#') {
                return None;
            }

            let mut parts = line.split('|').map(str::trim);
            let id = parts.next()?.parse::<i32>().ok()?;
            let status = parts.next()?;
            let code = parts.next()?;

            if id >= 0 && status == "active" {
                Some(code.to_string())
            } else {
                None
            }
        })
        .fold(Vec::new(), |mut acc, code| {
            acc.push(code);
            acc
        })
}

