}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub retries: Option<u8>,
}

impl Config {
    pub fn default_config() -> Self {
        Self {
            host: "localhost".to_string(),
            port: 8080,
            use_tls: false,
            retries: 3,
        }
    }
}

pub fn merge_config(
    defaults: Config,
    env: PartialConfig,
    user: PartialConfig,
) -> Result<Config, &'static str> {
    let mut merged = defaults;

    if let Some(host) = user.host {
        merged.host = host;
    } else if let Some(host) = env.host {
        merged.host = host;
    }

    if let Some(port) = env.port {
        merged.port = port;
    } else if let Some(port) = user.port {
        merged.port = port;
    }

    if let Some(use_tls) = env.use_tls {
        merged.use_tls = use_tls;
    }

    if let Some(retries) = user.retries {
        merged.retries = retries;
    } else if let Some(retries) = env.retries {
        merged.retries = retries;
    }

    if merged.use_tls && merged.port == 80 {
        merged.port = 443;
    }

    if merged.port == 0 {
        return Err("invalid port");
    }

    Ok(merged)
}

