use std::cmp::Reverse;
use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
    pub wins: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut best_by_name: HashMap<&str, &Player> = HashMap::new();

    for p in players {
        best_by_name
            .entry(&p.name)
            .and_modify(|cur| {
                if p.score > cur.score {
                    *cur = p;
                }
            })
            .or_insert(p);
    }

    let mut ranked: Vec<&Player> = best_by_name.into_values().collect();
    ranked.sort_by_key(|p| (p.score, Reverse(p.wins), p.name.clone()));
    ranked.into_iter().map(|p| p.name.clone()).collect()
}

