    fn ranks_by_score_then_wins_then_name() {
        let players = vec![
            p("dave", 12, 4),
            p("anna", 18, 3),
            p("cara", 18, 5),
            p("brad", 18, 5),
            p("erin", 12, 6),
        ];

        assert_eq!(
            rank_players(&players),
            vec!["brad", "cara", "anna", "erin", "dave"]
        );
    }

