use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order {
    pub region: &'static str,
    pub channel: &'static str,
    pub amount_cents: i64,
    pub refunded: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ChannelReport {
    pub region: String,
    pub recognized_cents: i64,
    pub refunded_orders: usize,
    pub top_channel: String,
    pub top_channel_cents: i64,
}

pub fn summarize(orders: &[Order]) -> Vec<ChannelReport> {
    let mut gross_by_region: BTreeMap<&str, i64> = BTreeMap::new();
    let mut refunded_by_region: BTreeMap<&str, usize> = BTreeMap::new();
    let mut channel_totals: BTreeMap<(&str, &str), i64> = BTreeMap::new();

    for order in orders {
        *gross_by_region.entry(order.region).or_insert(0) += order.amount_cents;
        if order.refunded {
            *refunded_by_region.entry(order.region).or_insert(0) += 1;
        }
        *channel_totals.entry((order.region, order.channel)).or_insert(0) += order.amount_cents;
    }

    let mut reports = Vec::new();
    for (region, gross) in gross_by_region {
        let refunded_orders = refunded_by_region.get(region).copied().unwrap_or(0);
        let mut top_channel = "";
        let mut top_channel_cents = -1;
        for ((r, channel), cents) in &channel_totals {
            if *r == region && *cents >= top_channel_cents {
                top_channel = channel;
                top_channel_cents = *cents;
            }
        }

        reports.push(ChannelReport {
            region: region.to_string(),
            recognized_cents: gross,
            refunded_orders,
            top_channel: top_channel.to_string(),
            top_channel_cents,
        });
    }

    reports.sort_by(|a, b| a.region.cmp(&b.region));
    reports
}

