            Order { region: "north", channel: "partner", amount_cents: 1000, refunded: false },
            Order { region: "south", channel: "store", amount_cents: 3000, refunded: true },
            Order { region: "south", channel: "web", amount_cents: 3000, refunded: false },
            Order { region: "south", channel: "store", amount_cents: 3000, refunded: false },
            Order { region: "west", channel: "web", amount_cents: -500, refunded: false },
            Order { region: "west", channel: "store", amount_cents: 0, refunded: false },
        ]
    }

    #[test]
