#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
    pub tags: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
    pub tags: Option<Vec<String>>,
}

pub fn merge_config(
    defaults: &Config,
    env: &PartialConfig,
    user: &PartialConfig,
) -> Result<Config, String> {
    let host = defaults.host.clone();
    let port = user.port.or(env.port).unwrap_or(defaults.port);
    let use_tls = user.use_tls.or(env.use_tls).unwrap_or(defaults.use_tls);
    let timeout_ms = user
        .timeout_ms
        .or(env.timeout_ms)
        .unwrap_or(defaults.timeout_ms);

    let tags = if let Some(ref env_tags) = env.tags {
        env_tags.clone()
    } else if let Some(ref user_tags) = user.tags {
        user_tags.clone()
    } else {
        defaults.tags.clone()
    };

    if port == 0 {
        return Err("port must be non-zero".into());
    }
    if timeout_ms < 100 {
        return Err("timeout_ms must be at least 100".into());
    }

    Ok(Config {
        host,
        port,
        use_tls,
        timeout_ms,
        tags,
    })
}

