#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<&'static str> {
    let mut rows: Vec<&Player> = players.iter().collect();
    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.name.cmp(&b.name))
    });
    rows.into_iter().map(|p| p.name).collect()
}

#[cfg(test)]
