            Player { name: "Ana", points: 15, wins: 1 },
            Player { name: "Bea", points: 15, wins: 4 },
            Player { name: "Zed", points: 9, wins: 8 },
        ];

        assert_eq!(rank_players(&players), vec!["Bea", "Ana", "Kai", "Zed"]);
    }

    #[test]
    fn uses_alphabetical_name_as_final_tiebreaker() {
