use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub category: &'static str,
    pub amount: i32,
    pub included: bool,
}

pub fn category_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (usize, i32)> = BTreeMap::new();

    for entry in entries {
        let row = totals.entry(entry.category).or_insert((0, 0));
        row.0 += 1;
        row.1 += entry.amount;
    }

    let mut out = String::new();
    let mut grand_total = 0;

    for (category, (count, total)) in totals {
        grand_total += total;
        out.push_str(&format!("{}: count={}, total={}\n", category, count, total));
    }

    out.push_str(&format!("grand_total={}", grand_total));
    out
}

