            Entry { category: "food", amount: 7, included: false },
            Entry { category: "tools", amount: -3, included: true },
            Entry { category: "books", amount: 12, included: true },
            Entry { category: "food", amount: 5, included: true },
        ];

        let report = category_report(&entries);
        assert_eq!(
            report,
            "books: count=1, total=12\nfood: count=1, total=5\ntools: count=2, total=7\ngrand_total=24"
        );
    }

