#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    InReview,
    Approved,
    Rejected,
    Published,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
    Restore,
}

pub fn apply_event(state: State, event: Event) -> State {
    match (state, event) {
        (State::Draft, Event::Submit) => State::InReview,
        (State::InReview, Event::Approve) => State::Approved,
        (State::InReview, Event::Reject) => State::Rejected,
        (State::Rejected, Event::Revise) => State::Draft,
        (State::Approved, Event::Publish) => State::Published,
        (State::Published, Event::Archive) => State::Archived,
        (State::Archived, Event::Restore) => State::Draft,
        (State::Rejected, Event::Submit) => State::InReview,
        (State::Approved, Event::Reject) => State::Rejected,
        _ => state,
    }
}

pub fn apply_events(mut state: State, events: &[Event]) -> State {
    for &event in events {
        state = apply_event(state, event);
    }
    state
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn happy_path_reaches_published() {
        let events = [Event::Submit, Event::Approve, Event::Publish];
        assert_eq!(apply_events(State::Draft, &events), State::Published);
    }

    #[test]
    fn rejected_items_must_be_revised_before_resubmission() {
        let events = [Event::Submit, Event::Reject, Event::Submit];
        assert_eq!(apply_events(State::Draft, &events), State::Rejected);

        let revised = [Event::Submit, Event::Reject, Event::Revise, Event::Submit];
        assert_eq!(apply_events(State::Draft, &revised), State::InReview);
    }

    #[test]
    fn approved_items_do_not_go_back_to_rejected() {
        let events = [Event::Submit, Event::Approve, Event::Reject];
        assert_eq!(apply_events(State::Draft, &events), State::Approved);
    }

    #[test]
    fn archived_items_restore_to_published_not_draft() {
        let events = [Event::Submit, Event::Approve, Event::Publish, Event::Archive, Event::Restore];
        assert_eq!(apply_events(State::Draft, &events), State::Published);
    }

    #[test]
    fn archive_only_allowed_from_published() {
        assert_eq!(apply_event(State::Approved, Event::Archive), State::Approved);
        assert_eq!(apply_event(State::Draft, Event::Archive), State::Draft);
        assert_eq!(apply_event(State::Published, Event::Archive), State::Archived);
    }
}

