#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Layer {
    pub endpoint: Option<&'static str>,
    pub retries: Option<u8>,
    pub timeout_ms: Option<u64>,
    pub use_tls: Option<bool>,
    pub headers: Vec<(&'static str, &'static str)>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Config {
    pub endpoint: &'static str,
    pub retries: u8,
    pub timeout_ms: u64,
    pub use_tls: bool,
    pub headers: Vec<(&'static str, &'static str)>,
}

pub fn merge_config(defaults: &Layer, base: &Layer, env: &Layer, user: &Layer) -> Config {
    let endpoint = user
        .endpoint
        .or(env.endpoint)
        .or(base.endpoint)
        .or(defaults.endpoint)
        .unwrap_or("http://localhost");

    let retries = user
        .retries
        .or(env.retries)
        .or(base.retries)
        .or(defaults.retries)
        .unwrap_or(3);

    let mut timeout_ms = defaults.timeout_ms.unwrap_or(1000);
    if let Some(v) = base.timeout_ms {
        timeout_ms = v;
    }
    if let Some(v) = env.timeout_ms {
        timeout_ms = v;
    }
    timeout_ms = user.timeout_ms.unwrap_or(1000);

    let use_tls = user.use_tls.unwrap_or(
        env.use_tls.unwrap_or(base.use_tls.unwrap_or(defaults.use_tls.unwrap_or(true))),
    );

    let mut headers = defaults.headers.clone();
    headers.extend(base.headers.iter().copied());
    headers.extend(env.headers.iter().copied());
    headers.extend(user.headers.iter().copied());

    Config {
        endpoint,
        retries,
        timeout_ms,
        use_tls,
        headers,
    }
}

