#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    for slot in existing {
        if candidate.start >= slot.start && candidate.start <= slot.end {
            return false;
        }
        if candidate.end >= slot.start && candidate.end <= slot.end {
            return false;
        }
    }
    true
}

