#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub name: String,
    pub active: bool,
    pub score: Option<u8>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (line_no, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut name = None;
        let mut active = None;
        let mut score = None;

        for field in line.split(';') {
            let (key, value) = field
                .split_once('=')
                .ok_or_else(|| format!("line {}: bad field", line_no + 1))?;
            let key = key.trim();
            let value = value.trim();

            match key {
                "id" => {
                    id = Some(
                        value
                            .parse::<u32>()
                            .map_err(|_| format!("line {}: invalid id", line_no + 1))?,
                    );
                }
                "name" => {
                    name = Some(value.to_string());
                }
                "active" => {
                    active = Some(match value {
                        "true" => true,
                        "false" => false,
                        _ => return Err(format!("line {}: invalid active", line_no + 1)),
                    });
                }
                "score" => {
                    score = Some(
                        value
                            .parse::<u8>()
                            .map_err(|_| format!("line {}: invalid score", line_no + 1))?,
                    );
                }
                _ => return Err(format!("line {}: unknown field {}", line_no + 1, key)),
            }
        }

        out.push(Record {
            id: id.ok_or_else(|| format!("line {}: missing id", line_no + 1))?,
            name: name.ok_or_else(|| format!("line {}: missing name", line_no + 1))?,
            active: active.ok_or_else(|| format!("line {}: missing active", line_no + 1))?,
            score,
        });
    }

    Ok(out)
}

#[cfg(test)]
