    use super::*;

    #[test]
    fn parses_valid_records_with_optional_blank_score() {
        let input = "id=1; name=Alice; active=true; score=42\nid=2;name=Bob;active=false;score=\nid=3;name=Cara;active=true";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    id: 1,
                    name: "Alice".into(),
                    active: true,
                    score: Some(42),
                },
                Record {
                    id: 2,
                    name: "Bob".into(),
                    active: false,
                    score: None,
                },
                Record {
                    id: 3,
                    name: "Cara".into(),
                    active: true,
                    score: None,
                }
            ]
        );
    }

    #[test]
    fn rejects_empty_name_and_out_of_range_score() {
        let err = parse_records("id=4;name= ;active=true;score=5").unwrap_err();
        assert_eq!(err, "line 1: empty name");

        let err = parse_records("id=5;name=Eve;active=false;score=101").unwrap_err();
        assert_eq!(err, "line 1: invalid score");
    }
}

