#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Shipment {
    pub region: &'static str,
    pub status: &'static str,
    pub units: u32,
}

pub fn summarize_shipments(rows: &[Shipment]) -> Vec<String> {
    let mut by_region: BTreeMap<&str, (u32, u32, u32)> = BTreeMap::new();

    for row in rows {
        let entry = by_region.entry(row.region).or_insert((0, 0, 0));
        entry.0 += 1;
        if row.status == "delivered" {
            entry.1 += row.units;
        }
        if row.status == "returned" {
            entry.2 += row.units;
        }
    }

    by_region
        .into_iter()
        .map(|(region, (orders, delivered_units, returned_units))| {
            let net_units = delivered_units + returned_units;
            format!(
                "region={region}; orders={orders}; delivered_units={delivered_units}; returned_units={returned_units}; net_units={net_units}"
            )
        })
        .collect()
}

