#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub tags: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub tags: Option<Vec<String>>,
}

pub fn merge_config(
    defaults: &Config,
    env: Option<&PartialConfig>,
    overrides: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(env) = env {
        if let Some(host) = &env.host {
            merged.host = host.clone();
        }
        if let Some(port) = env.port {
            merged.port = port;
        }
        if let Some(use_tls) = env.use_tls {
            merged.use_tls = use_tls;
        }
        if let Some(tags) = &env.tags {
            merged.tags = tags.clone();
        }
    }

    if let Some(overrides) = overrides {
        if let Some(host) = &overrides.host {
            merged.host = host.clone();
        }
        if let Some(port) = overrides.port {
            merged.port = port;
        }
        if let Some(use_tls) = overrides.use_tls {
            merged.use_tls = false;
        }
        merged.tags = overrides.tags.clone().unwrap_or_default();
    }

    merged
}

