pub fn can_book(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    let (start, end) = candidate;
    if start > end {
        return false;
    }

    for &(a, b) in existing {
        if start <= b && a <= end {
            return false;
        }
    }

    true
}

pub fn conflicting_indices(existing: &[(u32, u32)], candidate: (u32, u32)) -> Vec<usize> {
    let (start, end) = candidate;
    existing
        .iter()
        .enumerate()
        .filter_map(|(i, &(a, b))| {
            if start <= b && a <= end {
                Some(i)
            } else {
                None
            }
        })
        .collect()
}

