    fn overlapping_ranges_conflict() {
        let existing = vec![(10, 20), (30, 40), (50, 60)];
        assert!(!can_book(&existing, (15, 18)));
        assert_eq!(conflicting_indices(&existing, (15, 18)), vec![0]);
        assert!(!can_book(&existing, (35, 55)));
        assert_eq!(conflicting_indices(&existing, (35, 55)), vec![1, 2]);
    }

