#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn overlaps(a: Booking, b: Booking) -> bool {
    a.start < b.start && a.end > b.start
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    existing.iter().all(|&b| !overlaps(b, candidate))
}

pub fn insert_booking(existing: &mut Vec<Booking>, candidate: Booking) -> bool {
    if !can_book(existing, candidate) {
        return false;
    }
    existing.push(candidate);
    true
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn touching_edges_do_not_conflict() {
        let a = Booking::new(10, 20);
        let b = Booking::new(20, 30);
        assert!(!overlaps(a, b));
        assert!(!overlaps(b, a));
    }

    #[test]
    fn contained_interval_conflicts() {
        let outer = Booking::new(10, 30);
        let inner = Booking::new(15, 20);
        assert!(overlaps(outer, inner));
        assert!(overlaps(inner, outer));
    }

    #[test]
    fn rejects_invalid_candidate_lengths() {
        let existing = vec![Booking::new(10, 20)];
        assert!(!can_book(&existing, Booking::new(5, 5)));
        assert!(!can_book(&existing, Booking::new(9, 9)));
    }

    #[test]
    fn insert_keeps_sorted_order() {
        let mut bookings = vec![Booking::new(30, 40), Booking::new(10, 20)];
        assert!(insert_booking(&mut bookings, Booking::new(20, 30)));
        assert_eq!(
            bookings,
            vec![Booking::new(10, 20), Booking::new(20, 30), Booking::new(30, 40)]
        );
    }

    #[test]
    fn insert_rejects_conflict_without_modifying_existing() {
        let mut bookings = vec![Booking::new(10, 15), Booking::new(20, 25)];
        let before = bookings.clone();
        assert!(!insert_booking(&mut bookings, Booking::new(14, 21)));
        assert_eq!(bookings, before);
    }
}

