use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub player: String,
    pub points: i32,
    pub wins: u32,
    pub losses: u32,
}

pub fn rank_players(entries: &[Entry], limit: usize) -> Vec<String> {
    let mut merged: HashMap<String, Entry> = HashMap::new();

    for e in entries {
        let slot = merged.entry(e.player.clone()).or_insert_with(|| Entry {
            player: e.player.clone(),
            points: 0,
            wins: 0,
            losses: 0,
        });
        slot.points += e.points;
        slot.wins += e.wins;
        slot.losses += e.losses;
    }

    let mut items: Vec<Entry> = merged.into_values().collect();
    items.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.player.cmp(&b.player))
    });

    items
        .into_iter()
        .take(limit)
        .map(|e| format!("{}:{}-{} ({})", e.player, e.wins, e.losses, e.points))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::{rank_players, Entry};

    #[test]
    fn merges_duplicate_players_and_sorts_by_all_tiebreaks() {
        let entries = vec![
            Entry { player: "Mira".into(), points: 10, wins: 3, losses: 2 },
            Entry { player: "Zed".into(), points: 12, wins: 2, losses: 0 },
            Entry { player: "Mira".into(), points: 2, wins: 1, losses: 0 },
            Entry { player: "Ava".into(), points: 12, wins: 2, losses: 1 },
            Entry { player: "Nia".into(), points: 12, wins: 4, losses: 3 },
            Entry { player: "Omar".into(), points: 12, wins: 4, losses: 1 },
        ];

        let ranked = rank_players(&entries, 10);
