                "Zed (12 pts, 2-0)",
                "Ava (12 pts, 2-1)",
                "Mira (12 pts, 4-2)",
            ]
        );
    }

    #[test]
    fn uses_alphabetical_name_as_final_tiebreak_and_applies_limit_after_sorting() {
        let entries = vec![
            Entry { player: "Luca".into(), points: 9, wins: 3, losses: 1 },
            Entry { player: "Iris".into(), points: 9, wins: 3, losses: 1 },
            Entry { player: "Kai".into(), points: 11, wins: 1, losses: 0 },
