    pub transactions: usize,
    pub unique_reps: usize,
    pub refunds: usize,
}

pub fn summarize_sales(sales: &[Sale], min_net_total: i32) -> Vec<RegionSummary> {
    let mut grouped: BTreeMap<&str, RegionSummary> = BTreeMap::new();

    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert_with(|| RegionSummary {
            region: sale.region.to_string(),
            net_total: 0,
            transactions: 0,
            unique_reps: 0,
            refunds: 0,
        });

        entry.net_total += sale.amount;
        entry.transactions += 1;
        if sale.refunded {
            entry.refunds += 1;
        }
    }

    let mut out: Vec<RegionSummary> = grouped
        .into_values()
        .filter(|s| s.net_total > min_net_total)
        .collect();

    out.sort_by(|a, b| a.region.cmp(&b.region));
