enum Action {
    Copy { src: &'static str, dst: &'static str },
    Move { src: &'static str, dst: &'static str },
    Delete { target: &'static str },
    Archive { name: &'static str, items: usize },
}

enum Mode {
    Live,
    DryRun,
}

struct Task {
    id: &'static str,
    action: Action,
    mode: Mode,
}

fn describe(task: &Task) -> String {
    let label = match &task.action {
        Action::Copy { .. } => "copy",
        Action::Move { .. } => "copy",
        Action::Delete { .. } => "delete",
        Action::Archive { .. } => "archive",
    };

    let status = match (&task.action, &task.mode) {
        (Action::Delete { .. }, Mode::DryRun) => "dry-run".to_string(),
        (Action::Copy { src, dst }, _) | (Action::Move { src, dst }, _) if src == dst => {
            "blocked(same path)".to_string()
        }
        (Action::Copy { dst, .. }, _) | (Action::Move { dst, .. }, _) if dst.is_empty() => {
            "blocked(missing dst)".to_string()
        }
        (Action::Archive { items, .. }, _) if *items == 0 => "blocked(empty archive)".to_string(),
        _ => "ready".to_string(),
    };

    format!("{}:{}@{}", task.id, label, status)
}

fn main() {
    let tasks = [
        Task {
            id: "A",
            action: Action::Copy {
                src: "alpha.txt",
                dst: "backup/alpha.txt",
            },
            mode: Mode::Live,
        },
        Task {
            id: "B",
            action: Action::Move {
                src: "tmp/report.csv",
                dst: "",
            },
            mode: Mode::Live,
        },
        Task {
            id: "C",
            action: Action::Delete {
                target: "old.log",
            },
            mode: Mode::DryRun,
        },
        Task {
            id: "D",
            action: Action::Archive { name: "", items: 3 },
            mode: Mode::Live,
        },
        Task {
            id: "E",
