fn overlaps(existing: (u32, u32), candidate: (u32, u32)) -> bool {
    let (a_start, a_end) = existing;
    let (b_start, b_end) = candidate;
    a_start <= b_end && b_start <= a_end
}

fn can_book(booked: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    booked.iter().all(|&slot| !overlaps(slot, candidate))
}

