struct Team {
    name: &'static str,
    points: u32,
    goals_for: i32,
    goals_against: i32,
    wins: u32,
}

impl Team {
    fn goal_diff(&self) -> i32 {
        self.goals_against - self.goals_for
    }
}

fn standings(mut teams: Vec<Team>) -> String {
    teams.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then_with(|| a.goal_diff().cmp(&b.goal_diff()))
            .then_with(|| a.goals_for.cmp(&b.goals_for))
            .then_with(|| a.wins.cmp(&b.wins))
            .then_with(|| b.name.cmp(&a.name))
    });

    teams
        .iter()
        .enumerate()
        .map(|(i, t)| {
            format!(
                "{}. {} {} pts gd {:+} gs {} w {}",
                i + 1,
                t.name,
                t.points,
                t.goal_diff(),
                t.goals_for,
                t.wins
            )
        })
        .collect::<Vec<_>>()
        .join("\n")
}

