use std::fmt;

#[derive(Clone, Copy)]
enum Status {
    New,
    InProgress,
    Closed,
}

impl fmt::Display for Status {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let s = match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
        };
        write!(f, "{}", s)
    }
}

fn apply_event(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "resolve" => Status::Closed,
        "reopen" => Status::Closed,
        _ => status,
    }
}

fn main() {
    let data = [
        ("A", vec!["start", "resolve"]),
        ("B", vec!["start", "resolve", "reopen"]),
        ("C", vec!["resolve"]),
    ];

    let mut lines = Vec::new();
    for (id, events) in data {
        let mut status = Status::New;
        for event in events {
            status = apply_event(status, event);
        }
        lines.push(format!("{}: {}", id, status));
    }

    println!("{}", lines.join("\n"));
}

steps.replace:
