use std::fmt::Write;

#[derive(Clone, Debug)]
struct Config {
    host: Option<&'static str>,
    port: Option<u16>,
    mode: Option<&'static str>,
    features: Vec<&'static str>,
}

fn merge(defaults: &Config, file: &Config, env: &Config, cli: &Config) -> Config {
    let host = defaults.host.or(file.host).or(env.host).or(cli.host);
    let port = defaults.port.or(file.port).or(env.port).or(cli.port);
    let mode = defaults.mode.or(file.mode).or(env.mode).or(cli.mode);

    let mut features = Vec::new();
    features.extend(defaults.features.iter().copied());
    features.extend(file.features.iter().copied());
    features.extend(env.features.iter().copied());

    Config { host, port, mode, features }
}

fn render(cfg: &Config) -> String {
    let mut out = String::new();
    writeln!(&mut out, "host={}", cfg.host.unwrap_or("-")) .unwrap();
    writeln!(&mut out, "port={}", cfg.port.unwrap_or(0)).unwrap();
    writeln!(&mut out, "mode={}", cfg.mode.unwrap_or("-")) .unwrap();
    write!(&mut out, "features={}", cfg.features.join(",")).unwrap();
    out
}

