fn parse_time(s: &str) -> i32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<i32>().unwrap() * 60 + m.parse::<i32>().unwrap()
}

fn overlaps(a: (&str, &str), b: (&str, &str)) -> bool {
    let a_start = parse_time(a.0);
    let a_end = parse_time(a.1);
    let b_start = parse_time(b.0);
    let b_end = parse_time(b.1);

    a_start <= b_end && b_start <= a_end
}

