use std::collections::HashMap;

#[derive(Clone, Default)]
struct Team {
    pts: i32,
    gf: i32,
    ga: i32,
}

impl Team {
    fn gd(&self) -> i32 {
        self.gf - self.ga
    }
}

fn apply(stats: &mut HashMap<String, Team>, home: &str, away: &str, hg: i32, ag: i32) {
    let home_team = stats.entry(home.to_string()).or_default();
    home_team.gf += hg;
    home_team.ga += ag;

    let away_team = stats.entry(away.to_string()).or_default();
    away_team.gf += ag;
    away_team.ga += hg;

    if hg > ag {
        stats.get_mut(home).unwrap().pts += 3;
    } else if hg < ag {
        stats.get_mut(away).unwrap().pts += 3;
    } else {
        stats.get_mut(home).unwrap().pts += 1;
        stats.get_mut(away).unwrap().pts += 1;
    }
}

fn main() {
    let input = "\
Lynx,Hawks,2,1
Owls,Foxes,3,0
Bears,Lynx,1,1
Hawks,Owls,2,0
Foxes,Bears,1,4
Lynx,Owls,1,2
Bears,Hawks,0,0
Owls,Bears,0,2
Foxes,Lynx,0,0
Hawks,Hawks,9,9
bad,line
";

    let mut stats: HashMap<String, Team> = HashMap::new();

    for line in input.lines() {
        let parts: Vec<_> = line.split(',').collect();
        if parts.len() < 4 {
            continue;
        }
        let home = parts[0];
        let away = parts[1];
        let hg = parts[2].parse::<i32>().unwrap_or(0);
        let ag = parts[3].parse::<i32>().unwrap_or(0);
        apply(&mut stats, home, away, hg, ag);
    }

    let mut rows: Vec<_> = stats.into_iter().collect();
    rows.sort_by(|a, b| {
        b.1.pts
            .cmp(&a.1.pts)
            .then(b.1.gd().cmp(&a.1.gd()))
            .then(a.0.cmp(&b.0))
    });

    for (idx, (name, team)) in rows.iter().enumerate() {
        println!("{}. {} pts={} gd={} gf={}", idx + 1, name, team.pts, team.gd(), team.gf);
    }
}

