fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn format_names(items: &[&str]) -> String {
    format!("[{}]", items.join(", "))
}

fn main() {
    let requests = [
        Booking { name: "A", start: 10, end: 12 },
        Booking { name: "B", start: 12, end: 14 },
        Booking { name: "C", start: 9, end: 10 },
        Booking { name: "D", start: 11, end: 13 },
        Booking { name: "E", start: 14, end: 16 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<&str> = Vec::new();

    for req in requests {
        let conflict = accepted.iter().any(|existing| overlaps(&req, existing));
        if conflict {
            rejected.push(req.name);
        } else {
            accepted.push(req);
        }
    }

    let accepted_names: Vec<&str> = rejected.iter().copied().collect();
    let rejected_names: Vec<&str> = accepted.iter().map(|b| b.name).collect();

    println!("accepted: {}", format_names(&accepted_names));
    println!("rejected: {}", format_names(&rejected_names));
}

