use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Closed,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
        }
    }
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "create" => Status::Open,
        "start" => Status::InProgress,
        "resolve" => Status::Closed,
        "reopen" => Status::Open,
        "close" => Status::InProgress,
        _ => status,
    }
}

fn main() {
    let events = [
        ("A", "create"),
        ("A", "start"),
        ("A", "resolve"),
        ("B", "create"),
        ("B", "start"),
        ("C", "create"),
        ("C", "resolve"),
        ("C", "reopen"),
        ("C", "close"),
    ];

    let mut states = BTreeMap::new();
    for (id, event) in events {
        let current = states.get(id).copied().unwrap_or(Status::Open);
        states.insert(id, apply(current, event));
    }

    for id in ["A", "B", "C"] {
        let status = states.get(id).copied().unwrap_or(Status::Open);
        println!("{}: {}", id, status.as_str());
    }
}

