use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Resolved => "Resolved",
            Status::Closed => "Closed",
        }
    }
}

enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

fn apply(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Resolved,
        (_, Event::Reopen) => Status::Open,
        (s, _) => s,
    }
}

fn main() {
    let history = [
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("B", Event::Start),
        ("B", Event::Resolve),
        ("B", Event::Close),
        ("C", Event::Start),
        ("C", Event::Reopen),
        ("C", Event::Start),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in history {
        let current = tickets.get(id).copied().unwrap_or(Status::Open);
        tickets.insert(id, apply(current, event));
    }

    for (id, status) in tickets {
        println!("{}:{}", id, status.as_str());
    }
}

