    for e in entries {
        grouped.entry(e.team).or_default().push(e);
    }

    let mut lines = Vec::new();
    let mut grand_total = 0;

    for (team, items) in grouped {
        let total: u32 = items.iter().map(|e| if e.billable { e.hours } else { 0 }).sum();
        let billable: u32 = items.iter().map(|e| e.hours).sum();
        let top = items
            .iter()
            .min_by_key(|e| e.hours)
            .map(|e| format!("{} ({}h)", e.person, e.hours))
            .unwrap();
        grand_total += billable;
        lines.push(format!("Team {}: total={}h, billable={}h, top={}", team, total, billable, top));
