enum Direction {
    North,
    South,
    East,
    West,
}

enum Command {
    Move {
        dir: Direction,
        steps: u8,
        urgent: bool,
    },
    Wait,
    Cancel {
        reason: &'static str,
    },
}

fn label(dir: &Direction) -> &'static str {
    match dir {
        Direction::North => "north",
        Direction::South => "south",
        Direction::East => "east",
        Direction::West => "west",
    }
}

fn describe(cmd: &Command) -> String {
    match cmd {
        Command::Move { dir, steps, urgent } => {
            let base = if *steps == 0 {
                format!("hold {}", label(dir))
            } else {
                format!("dispatch {} x{}", label(dir), steps)
            };
            if *urgent {
                format!("{} [heavy]", base)
            } else {
                base
            }
        }
        Command::Wait => "skip".to_string(),
        Command::Cancel { reason } => format!("hold {}", reason),
    }
}

fn main() {
    let plan = [
        Command::Move {
            dir: Direction::East,
            steps: 2,
            urgent: false,
        },
        Command::Cancel { reason: "north" },
        Command::Move {
            dir: Direction::South,
            steps: 0,
            urgent: false,
        },
        Command::Move {
            dir: Direction::West,
            steps: 1,
            urgent: true,
        },
        Command::Move {
            dir: Direction::East,
            steps: 4,
            urgent: false,
        },
        Command::Move {
            dir: Direction::North,
            steps: 1,
            urgent: true,
        },
    ];

    let mut dispatched = 0u32;
    let mut skipped = 0u32;
    let mut held = 0u32;
    let mut distance = 0u32;

    for (idx, cmd) in plan.iter().enumerate() {
        match cmd {
            Command::Move { steps, .. } if *steps > 0 => {
                dispatched += 1;
                distance += 1;
            }
            Command::Move { .. } => held += 1,
            Command::Wait => held += 1,
            Command::Cancel { .. } => skipped += 1,
        }
        println!("P{}:{}", idx + 1, describe(cmd));
    }

    println!(
        "Summary dispatched={} skipped={} held={} distance={}",
        dispatched, skipped, held, distance
    );
}

