use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    Open,
    InProgress,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "open",
            State::InProgress => "in_progress",
            State::Closed => "closed",
        }
    }
}

fn main() {
    let events = [
        ("T1", "create"),
        ("T1", "start"),
        ("T1", "resolve"),
        ("T2", "create"),
        ("T2", "resolve"),
        ("T2", "reopen"),
        ("T3", "create"),
        ("T3", "start"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for (id, event) in events {
        let next = match event {
            "create" => Some(State::Open),
            "start" => Some(State::Open),
            "resolve" => Some(State::Closed),
            "reopen" => Some(State::Open),
            _ => None,
        };

        if let Some(state) = next {
            tickets.insert(id, state);
        }
    }

    let mut lines = Vec::new();
    for (id, state) in tickets {
        lines.push(format!("{}:{}", id, state.as_str()));
    }
    println!("{}", lines.join("\n"));
}

fn overlaps(a_start: u32, a_end: u32, b_start: u32, b_end: u32) -> bool {
    a_start <= b_end && b_start <= a_end
}

fn first_conflict(bookings: &[(u32, u32)], start: u32, end: u32) -> Option<(u32, u32)> {
    for &(b_start, b_end) in bookings {
        if overlaps(start, end, b_start, b_end) {
            return Some((b_start, b_end));
        }
    }
    None
}

fn fmt_range(start: u32, end: u32) -> String {
    format!("{:02}-{:02}", start, end)
}

fn main() {
    let bookings = [(9, 11), (13, 15)];
    let requests = [(9, 10), (10, 12), (11, 12), (12, 14)];

    for (start, end) in requests {
        match first_conflict(&bookings, start, end) {
            Some((b_start, b_end)) => {
                println!(
                    "{} conflict with {}",
                    fmt_range(start, end),
                    fmt_range(b_start, b_end)
                );
            }
            None => println!("{} available", fmt_range(start, end)),
        }
    }
}

