struct Entry {
    name: &'static str,
    solved: u32,
    penalty: u32,
    last: u32,
}

fn build_report(mut entries: Vec<Entry>) -> String {
    entries.sort_by(|a, b| {
        a.solved
            .cmp(&b.solved)
            .then(a.penalty.cmp(&b.penalty))
            .then(a.last.cmp(&b.last))
            .then(a.name.cmp(&b.name))
    });

    let mut out = String::from("Contest Alpha\n");
    let mut rank = 1usize;
    let mut prev: Option<Entry> = None;

    for (i, e) in entries.iter().enumerate() {
        if let Some(p) = prev {
            if p.solved != e.solved || p.penalty != e.penalty || p.last != e.last || p.name != e.name {
                rank += 1;
            }
        }
        out.push_str(&format!(
            "{}. {} solved={} penalty={} last={}\n",
            rank,
            e.name,
            e.solved,
            e.penalty,
            e.last
        ));
        prev = Some(*e);
        if i + 1 == entries.len() {
            out.push_str(&format!("entries={} top_rank={}", entries.len(), rank));
        }
    }

    out
}

fn main() {
    let entries = vec![
        Entry { name: "Zoe", solved: 5, penalty: 310, last: 110 },
        Entry { name: "Ada", solved: 5, penalty: 310, last: 95 },
