use std::fmt::Write;

#[derive(Clone, Copy)]
struct Booking {
    name: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a_start: u32, a_end: u32, b_start: u32, b_end: u32) -> bool {
    a_start <= b_end && b_start <= a_end
}

fn conflicts(request: Booking, existing: &[Booking]) -> Option<Vec<&'static str>> {
    if request.start > request.end {
        return None;
    }

    let mut names = Vec::new();
    for b in existing {
        if overlaps(request.start, request.end, b.start, b.end) {
            names.push(b.name);
        }
    }
    Some(names)
}

fn render(request: Booking, existing: &[Booking]) -> String {
    let mut out = String::new();
    write!(
        &mut out,
        "{} [{},{}) -> ",
        request.name, request.start, request.end
    )
    .unwrap();

    match conflicts(request, existing) {
        None => out.push_str("invalid request"),
        Some(names) if names.is_empty() => out.push_str("conflicts: none"),
        Some(names) => {
            out.push_str("conflicts: ");
            out.push_str(&names.join(","));
        }
    }
    out
}

