#[derive(Clone, Copy)]
enum Event {
    Create,
    Pay,
    Ship,
    Deliver,
    Cancel,
    Return,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    Paid,
    Shipped,
    Delivered,
    Canceled,
    Returned,
}

fn apply(mut status: Option<Status>, event: Event) -> Option<Status> {
    use Event::*;
    use Status::*;

    status = match (status, event) {
        (None, Create) => Some(New),
        (Some(New), Pay) => Some(Paid),
        (Some(Paid), Ship) => Some(Shipped),
        (Some(Shipped), Deliver) => Some(Delivered),
        (_, Cancel) => Some(Canceled),
        (Some(Delivered), Return) => Some(Delivered),
        (s, _) => s,
    };

    status
}

fn label(status: Option<Status>) -> &'static str {
    match status {
        Some(Status::New) => "new",
        Some(Status::Paid) => "paid",
        Some(Status::Shipped) => "shipped",
        Some(Status::Delivered) => "done",
        Some(Status::Canceled) => "canceled",
        Some(Status::Returned) => "returned",
        None => "missing",
    }
}

fn main() {
    let cases = [
        (
            "A",
            [Event::Create, Event::Pay, Event::Ship, Event::Deliver],
        ),
        (
            "B",
            [Event::Create, Event::Pay, Event::Ship, Event::Deliver],
        ),
        ("C", [Event::Create, Event::Pay, Event::Cancel, Event::Ship]),
    ];

    for (id, events) in cases {
        let mut status = None;
        for event in events {
            status = apply(status, event);
        }
        println!("{}: {}", id, label(status));
    }
}

struct Record {
    name: &'static str,
    active: bool,
    score: Option<u8>,
    tags: &'static [&'static str],
}

fn summarize(records: &[Record]) -> Vec<String> {
    let mut counts = records
        .iter()
        .filter(|r| r.active)
        .flat_map(|r| {
            let weight = if r.score.unwrap_or(0) >= 80 { 2 } else { 1 };
            r.tags.iter().map(move |tag| ((*tag).to_string(), weight))
        })
        .fold(std::collections::BTreeMap::<String, usize>::new(), |mut acc, (tag, weight)| {
            *acc.entry(tag).or_insert(0) += weight;
            acc
        });

    counts.remove("misc");

    counts
        .into_iter()
        .filter(|(_, count)| *count >= 3)
        .map(|(tag, count)| format!("{}={}", tag, count))
        .collect()
}

fn main() {
    let records = [
        Record { name: "A", active: true, score: Some(90), tags: &["ops", "ui"] },
        Record { name: "B", active: true, score: Some(40), tags: &["ops", "low"] },
        Record { name: "C", active: false, score: Some(99), tags: &["ops", "ui"] },
        Record { name: "D", active: true, score: None, tags: &["low", "misc"] },
        Record { name: "E", active: true, score: Some(82), tags: &["ui", "low"] },
        Record { name: "F", active: true, score: Some(79), tags: &["ops"] },
    ];

    for line in summarize(&records) {
        println!("{}", line);
    }
}

enum Job {
    Send { channel: &'static str, msg: &'static str },
    Sum(Vec<i32>),
    Repeat { text: &'static str, times: usize },
    Report(Vec<i32>),
    Nop,
}

fn render(job: &Job) -> String {
    match job {
        Job::Send { channel, msg } => format!("send {} to {}", channel, msg),
        Job::Sum(nums) => format!("sum {:?} = {}", nums, nums.iter().product::<i32>()),
        Job::Repeat { text, times } => format!("repeat {} x{} = {}", text, times, text),
        Job::Report(nums) => {
            let total: i32 = nums.iter().sum();
            let avg = if nums.is_empty() { 0.0 } else { total as f64 / nums.len() as f64 };
            format!("report count={} total={} avg={:.0}", nums.len(), total, avg)
        }
        Job::Nop => "noop".to_string(),
    }
}

fn main() {
    let jobs = vec![
        Job::Send {
            channel: "alert",
            msg: "ops: disk low",
        },
        Job::Sum(vec![3, 4, 5]),
        Job::Repeat { text: "go", times: 3 },
        Job::Report(vec![2, 3, 4, 5]),
        Job::Nop,
    ];

    for job in jobs {
        println!("{}", render(&job));
    }
}

