    let requests = vec![
        Booking { id: "A", start: 540, end: 600 },
        Booking { id: "B", start: 600, end: 660 },
        Booking { id: "C", start: 570, end: 630 },
        Booking { id: "D", start: 660, end: 720 },
        Booking { id: "E", start: 630, end: 690 },
        Booking { id: "F", start: 720, end: 780 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<&str> = Vec::new();

    for req in requests {
        let conflict = accepted.iter().any(|slot| overlaps(slot, &req));
        if conflict {
            rejected.push(req.id);
        } else {
            accepted.push(req);
        }
    }

    let accepted_ids = accepted.iter().map(|b| b.id).collect::<Vec<_>>().join(",");
    let rejected_ids = rejected.join(",");
    let minutes: u32 = accepted.iter().map(|b| b.end - b.start).sum::<u32>() + rejected.len() as u32;

    println!("accepted: {}", accepted_ids);
    println!("rejected: {}", rejected_ids);
    println!("minutes: {}", minutes);
}

