}

fn parse_line(line: &str) -> Result<Record, &'static str> {
    let mut id = "";
    let mut kind = "";
    let mut qty = 0u32;

    for part in line.split(';') {
        let mut kv = part.splitn(2, '=');
        let k = kv.next().unwrap_or("");
        let v = kv.next().unwrap_or("");
        match k {
            "id" => id = v,
            "kind" => kind = v,
            "qty" => qty = v.parse::<u32>().unwrap_or(0),
            _ => {}
        }
    }

