use std::collections::BTreeMap;

fn main() {
    let rows = [
        ("Red", 10.0),
        ("Blue", 12.5),
        ("Red", 5.0),
        ("Blue", 2.5),
        ("Green", -3.0),
        ("Green", 7.25),
        ("Blue", 0.0),
    ];

    let mut grouped: BTreeMap<&str, (usize, f64)> = BTreeMap::new();
    for (team, amount) in rows {
        let entry = grouped.entry(team).or_insert((0, 0.0));
        entry.0 += 1;
        entry.1 += amount;
    }

    let mut items: Vec<_> = grouped.into_iter().collect();
    items.sort_by(|a, b| a.0.cmp(b.0));

    for (team, (count, total)) in items {
        println!("{}|{}|{:.2}", team, count, total);
    }
}

