use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event<'a> {
    Open { id: &'a str, owner: &'a str },
    Progress { id: &'a str },
    Reassign { id: &'a str, owner: &'a str },
    Resolve { id: &'a str },
    Reopen { id: &'a str },
}

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Clone, Copy)]
struct Ticket<'a> {
    status: Status,
    owner: &'a str,
    steps: usize,
}

fn main() {
    let events = [
        Event::Open { id: "A1", owner: "alice" },
        Event::Progress { id: "A1" },
        Event::Resolve { id: "A1" },
        Event::Reopen { id: "A1" },
        Event::Resolve { id: "A1" },
        Event::Open { id: "B2", owner: "bob" },
        Event::Resolve { id: "B2" },
        Event::Reassign { id: "B2", owner: "dana" },
        Event::Open { id: "C3", owner: "carol" },
        Event::Reassign { id: "C3", owner: "erin" },
        Event::Progress { id: "C3" },
        Event::Reopen { id: "C3" },
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();

    for event in events {
        match event {
            Event::Open { id, owner } => {
                tickets.insert(
                    id,
                    Ticket {
                        status: Status::Open,
                        owner,
                        steps: 1,
                    },
                );
            }
            Event::Progress { id } => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.status = Status::InProgress;
                    ticket.steps += 1;
                }
            }
            Event::Reassign { id, owner } => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.owner = owner;
                }
            }
            Event::Resolve { id } => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.status = Status::Closed;
                    ticket.steps += 1;
                }
            }
            Event::Reopen { id } => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.status = Status::Open;
                }
            }
        }
    }

    let mut lines = Vec::new();
    for (id, ticket) in tickets {
        let status = match ticket.status {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Resolved => "Resolved",
            Status::Closed => "Closed",
        };
        lines.push(format!("{}:{}@{}|assigned={}", id, status, ticket.steps, ticket.owner));
    }

    print!("{}", lines.join("\n"));
}

