fn summarize(input: &str) -> String {
    let kept: Vec<&str> = input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let name = parts.next()?;
            let enabled = parts.next()?;
            let score: i32 = parts.next()?.parse().ok()?;
            if enabled == "on" && score > 5 {
                Some(name)
            } else {
                None
            }
        })
        .collect();

    let skipped: Vec<&str> = input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let name = parts.next()?;
            let enabled = parts.next()?;
            let score: i32 = parts.next()?.parse().ok()?;
            if enabled == "off" || score <= 5 {
                Some(name)
            } else {
                None
            }
        })
        .collect();

    format!("keep:{}\nskip:{}", kept.join(","), skipped.join(","))
}

