enum Event {
    Created,
    PaymentCaptured,
    Packed,
    Shipped,
    Delivered,
    Refunded,
    PaymentFailed(&'static str),
}

fn summarize(events: &[Event]) -> String {
    let mut paid = false;
    let mut shipped = false;

    for event in events {
        match event {
            Event::PaymentCaptured => paid = true,
            Event::Packed => shipped = true,
            Event::Shipped => shipped = true,
            Event::Delivered => return "shipped".to_string(),
            Event::Refunded => return "paid".to_string(),
            Event::PaymentFailed(_) => return "error".to_string(),
            Event::Created => {}
        }
    }

    if shipped {
        "shipped".to_string()
    } else if paid {
        "paid".to_string()
    } else {
        "new".to_string()
    }
}

fn main() {
    let orders = [
        ("A100", vec![Event::Created, Event::PaymentCaptured, Event::Packed]),
        ("B200", vec![Event::Created, Event::PaymentCaptured, Event::Refunded]),
        ("C300", vec![Event::Created, Event::PaymentFailed("card declined")]),
        (
            "D400",
            vec![
                Event::Created,
                Event::PaymentCaptured,
                Event::Packed,
                Event::Shipped,
                Event::Delivered,
            ],
        ),
    ];

    for (id, events) in orders {
        println!("{}: {}", id, summarize(&events));
    }
}

