fn parse_score(line: &str) -> Option<(&str, i32)> {
    let mut parts = line.split('|');
    let user = parts.next()?;
    let kind = parts.next()?;
    let amount = parts.next()?.parse::<i32>().ok()?;
    let tag = parts.next()?;

    if kind != "score" {
        return None;
    }

    if tag == "test" {
        return None;
    }

    if amount < 0 {
        return Some((user, amount));
    }

    Some((user, amount))
}

fn main() {
    let input = [
        "ann|score|5|core",
        "bob|score|8|ops",
        "ann|score|3|bonus",
        "cara|skip|7|core",
        "dev|score|0|ops",
        "eve|score|6|core",
        "ann|score|4|test",
        "bob|score|-2|ops",
        "dev|score|8|ops",
        "ann|score|3|core",
        "zoe|score|9|test",
    ];

    let mut rows: Vec<(String, i32)> = input
        .iter()
        .filter_map(|line| parse_score(line))
        .map(|(user, amount)| (user.to_string(), amount))
        .collect();

    rows.sort_by(|a, b| a.0.cmp(&b.0));

    for (user, amount) in rows {
        println!("{}:{}", user, amount);
    }
}

