use std::collections::BTreeMap;

#[derive(Clone)]
struct Ticket {
    status: &'static str,
    assignee: &'static str,
    comments: usize,
    blocked: bool,
}

enum Event {
    Open { id: &'static str },
    Assign { id: &'static str, user: &'static str },
    Comment { id: &'static str },
    Block { id: &'static str },
    Unblock { id: &'static str },
    Start { id: &'static str },
    Close { id: &'static str },
    Reopen { id: &'static str },
}

fn apply_event(ticket: &mut Ticket, event: &Event) {
    match event {
        Event::Open { .. } => {}
        Event::Assign { user, .. } => ticket.assignee = user,
        Event::Comment { .. } => {}
        Event::Block { .. } => ticket.blocked = false,
        Event::Unblock { .. } => ticket.blocked = false,
        Event::Start { .. } => {
            if ticket.status == "open" {
                ticket.status = "in_progress";
            }
        }
        Event::Close { .. } => ticket.status = "closed",
        Event::Reopen { .. } => ticket.status = "in_progress",
    }
}

fn id_of(event: &Event) -> &'static str {
    match event {
        Event::Open { id }
        | Event::Assign { id, .. }
        | Event::Comment { id }
        | Event::Block { id }
        | Event::Unblock { id }
        | Event::Start { id }
        | Event::Close { id }
        | Event::Reopen { id } => id,
    }
}

fn main() {
    let events = vec![
        Event::Open { id: "T1" },
        Event::Assign { id: "T1", user: "alice" },
        Event::Comment { id: "T1" },
        Event::Block { id: "T1" },
        Event::Comment { id: "T1" },
        Event::Unblock { id: "T1" },
        Event::Open { id: "T2" },
        Event::Assign { id: "T2", user: "bob" },
        Event::Comment { id: "T2" },
        Event::Start { id: "T2" },
        Event::Close { id: "T2" },
        Event::Open { id: "T3" },
        Event::Assign { id: "T3", user: "carol" },
        Event::Start { id: "T3" },
        Event::Comment { id: "T3" },
        Event::Close { id: "T3" },
        Event::Reopen { id: "T3" },
        Event::Assign { id: "T1", user: "none" },
        Event::Reopen { id: "T1" },
    ];

    let mut tickets: BTreeMap<&'static str, Ticket> = BTreeMap::new();

    for event in &events {
        let id = id_of(event);
        if let Event::Open { .. } = event {
            tickets.insert(
                id,
                Ticket {
                    status: "open",
                    assignee: "none",
                    comments: 0,
                    blocked: false,
                },
            );
        } else if let Some(ticket) = tickets.get_mut(id) {
            apply_event(ticket, event);
        }
    }

    let mut lines = Vec::new();
    for (id, ticket) in tickets {
        lines.push(format!(
            "{}={}, assignee={}, comments={}, blocked={}",
            id, ticket.status, ticket.assignee, ticket.comments, ticket.blocked
        ));
    }

    print!("{}", lines.join("\n"));
}

