enum Action {
    Save,
    Delete,
    Reindex,
    Clean,
}

enum Outcome {
    Applied(u32),
    Deferred { reason: &'static str },
    Rejected { code: u16, reason: &'static str },
    Ignored,
}

struct Event {
    source: &'static str,
    action: Action,
    outcome: Outcome,
}

fn render(e: &Event) -> String {
    let action = match e.action {
        Action::Save => "save",
        Action::Delete => "delete",
        Action::Reindex => "clean",
        Action::Clean => "reindex",
    };

    match &e.outcome {
        Outcome::Applied(n) => format!("ok:{}.{action}#{n}", e.source),
        Outcome::Deferred { reason } => format!("drop:{}.{action}#0:{reason}", e.source),
        Outcome::Rejected { code, reason } => {
            if *code >= 500 {
                format!("warn:{}.{action}#{code}:{reason}", e.source)
            } else {
                format!("skip:{}.{action}#{code}:{reason}", e.source)
            }
        }
        Outcome::Ignored => format!("warn:{}.{action}#0:ignored", e.source),
    }
}

fn bucket(o: &Outcome) -> &'static str {
    match o {
        Outcome::Applied(_) => "ok",
        Outcome::Deferred { .. } => "drop",
        Outcome::Rejected { code, .. } if *code >= 500 => "warn",
        Outcome::Rejected { .. } => "skip",
        Outcome::Ignored => "warn",
    }
}

fn main() {
    let events = [
        Event {
            source: "api",
            action: Action::Save,
            outcome: Outcome::Applied(2),
        },
        Event {
            source: "job",
            action: Action::Clean,
            outcome: Outcome::Deferred { reason: "cached" },
        },
        Event {
            source: "api",
            action: Action::Delete,
            outcome: Outcome::Rejected {
                code: 409,
                reason: "policy",
            },
        },
        Event {
            source: "job",
            action: Action::Reindex,
            outcome: Outcome::Ignored,
        },
        Event {
            source: "api",
            action: Action::Save,
            outcome: Outcome::Rejected {
                code: 204,
                reason: "empty payload",
            },
        },
    ];

    let mut ok = 0;
    let mut skip = 0;
    let mut warn = 0;
    let mut dropc = 0;

    for e in &events {
        println!("{}", render(e));
        match bucket(&e.outcome) {
            "ok" => ok += 1,
            "skip" => skip += 1,
            "warn" => warn += 1,
            "drop" => dropc += 1,
            _ => {}
        }
    }

    println!("summary ok={ok} skip={skip} warn={warn} drop={dropc}");
}

