use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Done,
    Cancelled,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "open",
            State::InProgress => "progress",
            State::Blocked => "blocked",
            State::Done => "done",
            State::Cancelled => "cancelled",
        }
    }
}

#[derive(Clone, Debug)]
struct Ticket {
    state: State,
    owner: Option<&'static str>,
    history: Vec<State>,
}

impl Ticket {
    fn new() -> Self {
        Self {
            state: State::Open,
            owner: None,
            history: vec![State::Open],
        }
    }

    fn set_state(&mut self, next: State) {
        self.state = next;
        self.history.push(next);
    }
}

enum Event {
    Start(&'static str),
    Block,
    Resume,
    Finish,
    Cancel,
}

fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Start(name) => {
            ticket.owner = Some(name);
            ticket.set_state(State::InProgress);
        }
        Event::Block => {
            ticket.set_state(State::Blocked);
        }
        Event::Resume => {
            ticket.set_state(State::InProgress);
        }
        Event::Finish => {
            ticket.set_state(State::Done);
        }
        Event::Cancel => {
            ticket.set_state(State::Cancelled);
        }
    }
}

fn main() {
    let mut tickets: BTreeMap<&str, Ticket> = [
        ("T1", Ticket::new()),
        ("T2", Ticket::new()),
        ("T3", Ticket::new()),
        ("T4", Ticket::new()),
        ("T5", Ticket::new()),
    ]
    .into_iter()
    .collect();

    let events = vec![
        ("T1", Event::Start("amy")),
        ("T1", Event::Block),
        ("T1", Event::Resume),
        ("T1", Event::Finish),
        ("T2", Event::Start("ben")),
        ("T2", Event::Cancel),
        ("T2", Event::Finish),
        ("T3", Event::Block),
        ("T3", Event::Resume),
        ("T3", Event::Finish),
        ("T4", Event::Start("drew")),
        ("T4", Event::Block),
        ("T4", Event::Start("erin")),
        ("T5", Event::Finish),
    ];

    for (id, event) in events {
        let ticket = tickets.get_mut(id).unwrap();
        apply(ticket, event);
    }

    for (id, ticket) in tickets {
        let owner = ticket.owner.unwrap_or("none");
        let history = ticket
            .history
            .iter()
            .map(State::as_str)
            .collect::<Vec<_>>()
            .join(">>");
        println!("{}|{}|{}|{}", id, ticket.state.as_str(), owner, history);
    }
}

steps.replace:
Event::Cancel => {
    ticket.owner = None;
    ticket.set_state(State::Cancelled);
}

Event::Finish => {
    ticket.owner = None;
    ticket.set_state(State::Done);
}

Event::Start(name) => {
    if ticket.state == State::Open {
        ticket.owner = Some(name);
        ticket.set_state(State::InProgress);
    }
}

Event::Resume => {
    if ticket.state == State::Blocked {
        ticket.set_state(State::InProgress);
    }
}

Event::Block => {
    if matches!(ticket.state, State::Open | State::InProgress) {
        ticket.set_state(State::Blocked);
    }
}

