#[derive(Clone, Debug)]
struct Config {
    host: Option<String>,
    port: Option<u16>,
    timeout: Option<u32>,
    debug: Option<bool>,
    retries: Option<u8>,
    features: Vec<String>,
}

impl Config {
    fn new() -> Self {
        Self {
            host: None,
            port: None,
            timeout: None,
            debug: None,
            retries: None,
            features: Vec::new(),
        }
    }

    fn merge(mut self, layer: &Config) -> Self {
        if self.host.is_none() {
            self.host = layer.host.clone();
        }
        if self.port.is_none() {
            self.port = layer.port;
        }
        if self.timeout.is_none() {
            self.timeout = layer.timeout;
        }
        if self.debug.is_none() {
            self.debug = layer.debug;
        }
        if self.retries.is_none() {
            self.retries = layer.retries;
        }
        if self.features.is_empty() {
            self.features = layer.features.clone();
        }
        self
    }
}

fn join_features(items: &[String]) -> String {
    items.join(",")
}

