use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Booking {
    desk: &'static str,
    label: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn main() {
    let bookings = vec![
        Booking { desk: "deskA", label: "alpha", start: 540, end: 600 },
        Booking { desk: "deskA", label: "beta", start: 600, end: 630 },
        Booking { desk: "deskA", label: "gamma", start: 630, end: 690 },
        Booking { desk: "deskA", label: "delta", start: 660, end: 720 },
        Booking { desk: "deskA", label: "epsilon", start: 620, end: 650 },
        Booking { desk: "deskB", label: "eta", start: 540, end: 570 },
        Booking { desk: "deskB", label: "theta", start: 560, end: 580 },
        Booking { desk: "deskB", label: "zeta", start: 580, end: 620 },
    ];

    let mut accepted: Vec<&'static str> = Vec::new();
    let mut conflicts: BTreeMap<&'static str, Vec<String>> = BTreeMap::new();
    let mut accepted_by_desk: BTreeMap<&'static str, Vec<Booking>> = BTreeMap::new();

    for booking in bookings {
        let desk_bookings = accepted_by_desk.entry(booking.desk).or_default();
        let mut hit: Option<&'static str> = None;

        for existing in desk_bookings.iter() {
            if overlaps(existing, &booking) {
                hit = Some(existing.label);
            }
        }

        if let Some(existing_label) = hit {
            conflicts
                .entry(booking.desk)
                .or_default()
                .push(format!("{} vs {}", existing_label, booking.label));
        } else {
            accepted.push(booking.label);
            desk_bookings.push(booking);
        }
    }

    println!("accepted: {}", accepted.join(","));
    for (desk, entries) in conflicts {
        println!("{} conflicts:", desk);
        for entry in entries {
            println!("{}", entry);
        }
    }
}

steps.find:
fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

steps.replace:
fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start < b.end && b.start < a.end
}

steps.find:
for existing in desk_bookings.iter() {
    if overlaps(existing, &booking) {
        hit = Some(existing.label);
    }
}

steps.replace:
for existing in desk_bookings.iter() {
    if overlaps(existing, &booking) {
        hit = match hit {
            Some(current) if current < existing.label => Some(current),
            _ => Some(existing.label),
        };
    }
}

