use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    InProgress,
    Blocked,
    Closed,
    Cancelled,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
            Status::Cancelled => "Cancelled",
        }
    }
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Start,
    Block,
    Resolve,
    Close,
    Cancel,
}

#[derive(Clone, Copy)]
struct Ticket {
    status: Status,
    history_len: usize,
}

fn apply_event(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Create => {
            ticket.status = Status::New;
            ticket.history_len += 1;
        }
        Event::Start => {
            if ticket.status != Status::Closed {
                ticket.status = Status::InProgress;
                ticket.history_len += 1;
            }
        }
        Event::Block => {
            if ticket.status == Status::InProgress {
                ticket.status = Status::Blocked;
                ticket.history_len += 1;
            }
        }
        Event::Resolve => {
            if ticket.status == Status::Blocked {
                ticket.status = Status::InProgress;
            }
            ticket.history_len += 1;
        }
        Event::Close => {
            ticket.status = Status::Closed;
            ticket.history_len += 1;
        }
        Event::Cancel => {
            if ticket.status != Status::Closed {
                ticket.status = Status::Cancelled;
            }
            ticket.history_len += 1;
        }
    }
}

fn main() {
    let mut tickets = BTreeMap::new();
    tickets.insert(
        "A",
        Ticket {
            status: Status::New,
            history_len: 0,
        },
    );
    tickets.insert(
        "B",
        Ticket {
            status: Status::New,
            history_len: 0,
        },
    );
    tickets.insert(
        "C",
        Ticket {
            status: Status::New,
            history_len: 0,
        },
    );
    tickets.insert(
        "D",
        Ticket {
            status: Status::New,
            history_len: 0,
        },
    );

    let events = [
        ("A", Event::Create),
        ("A", Event::Start),
        ("A", Event::Block),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Create),
        ("B", Event::Start),
        ("B", Event::Block),
        ("B", Event::Resolve),
        ("B", Event::Close),
        ("C", Event::Create),
        ("C", Event::Start),
        ("C", Event::Cancel),
        ("C", Event::Close),
        ("D", Event::Create),
        ("D", Event::Start),
        ("D", Event::Block),
    ];

    for (id, event) in events {
        let ticket = tickets.get_mut(id).unwrap();
        apply_event(ticket, event);
    }

    for (id, ticket) in tickets {
        println!("{}:{}:{}", id, ticket.status.as_str(), ticket.history_len);
    }
}

