    let mut totals: Vec<(String, i32)> = input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split(',');
            let name = parts.next()?;
            let points = parse_points(parts.next()?)?;
            let tag = parts.next()?;
            if tag == "skip" {
                return None;
            }
            Some((name.to_string(), points))
        })
        .fold(Vec::new(), |mut acc, (name, pts)| {
            if let Some((_, total)) = acc.iter_mut().find(|(n, _)| *n == name) {
                *total += pts;
            } else {
                acc.push((name, pts));
            }
            acc
        });

    totals.sort_by(|a, b| a.1.cmp(&b.1).then(a.0.cmp(&b.0)));

