#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn summarize(entries: &[Entry], min_team_total: u32) -> String {
    let mut totals: BTreeMap<&str, u32> = BTreeMap::new();

    for entry in entries {
        *totals.entry(entry.team).or_insert(0) += entry.hours;
    }

    let mut lines = Vec::new();
    let mut grand_total = 0;

    for (team, total) in totals {
        if total >= min_team_total {
            lines.push(format!("{team}: {total}h"));
            grand_total += total;
        }
    }

    lines.push(format!("TOTAL: {grand_total}h"));
    lines.join("\n")
}

