#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    OnHold,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Pause,
    Resume,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;

    for event in events {
        status = match (status, *event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::InProgress, Event::Pause) => Status::OnHold,
            (Status::OnHold, Event::Resume) => Status::Open,
            (_, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (_, Event::Reopen) => Status::Open,
            (current, _) => current,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn resume_returns_to_in_progress_not_open() {
        let events = [Event::Start, Event::Pause, Event::Resume];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn resolve_only_works_from_active_states() {
        assert_eq!(apply_events(&[Event::Resolve]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve]), Status::Resolved);
        assert_eq!(apply_events(&[Event::Start, Event::Pause, Event::Resolve]), Status::Resolved);
    }

    #[test]
    fn reopen_only_works_from_resolved_or_closed() {
        assert_eq!(apply_events(&[Event::Reopen]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Reopen]), Status::InProgress);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Reopen]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Close, Event::Reopen]), Status::Open);
    }

    #[test]
    fn close_requires_resolved_first() {
        assert_eq!(apply_events(&[Event::Close]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Close]), Status::InProgress);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Close]), Status::Closed);
    }

    #[test]
    fn complex_transition_sequence_preserves_invariants() {
        let events = [
            Event::Start,
            Event::Pause,
            Event::Resume,
            Event::Resolve,
            Event::Close,
            Event::Reopen,
            Event::Pause,
            Event::Resolve,
            Event::Close,
        ];
        assert_eq!(apply_events(&events), Status::Closed);
    }
}

