use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

#[derive(Clone)]
struct Ticket {
    status: Status,
    blockers: u32,
}

impl Default for Ticket {
    fn default() -> Self {
        Self {
            status: Status::Open,
            blockers: 0,
        }
    }
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Resolve(&'a str),
    Reopen(&'a str),
}

fn apply_event(ticket: &mut Ticket, event: &Event<'_>) {
    match event {
        Event::Create(_) => {}
        Event::Start(_) => ticket.status = Status::InProgress,
        Event::Block(_) => {
            ticket.blockers += 1;
            ticket.status = Status::Blocked;
        }
        Event::Unblock(_) => {
            if ticket.blockers > 0 {
                ticket.blockers -= 1;
            }
            ticket.status = Status::InProgress;
        }
        Event::Resolve(_) => ticket.status = Status::Closed,
        Event::Reopen(_) => ticket.status = Status::Open,
    }
}

fn main() {
    let events = vec![
        Event::Create("T1"),
        Event::Start("T1"),
        Event::Block("T1"),
        Event::Unblock("T1"),
        Event::Resolve("T1"),
        Event::Reopen("T1"),
        Event::Resolve("T1"),
        Event::Create("T2"),
        Event::Resolve("T2"),
        Event::Reopen("T2"),
        Event::Start("T2"),
        Event::Create("T3"),
        Event::Start("T3"),
        Event::Block("T3"),
        Event::Resolve("T3"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    for event in &events {
        let id = match event {
            Event::Create(id)
            | Event::Start(id)
            | Event::Block(id)
            | Event::Unblock(id)
            | Event::Resolve(id)
            | Event::Reopen(id) => *id,
        };
        let ticket = tickets.entry(id).or_default();
        apply_event(ticket, event);
    }

    let mut open = 0;
    let mut closed = 0;
    let mut blocked = 0;

    for (id, ticket) in &tickets {
        println!("{}:{}:{}", id, ticket.status.as_str(), ticket.blockers);
        match ticket.status {
            Status::Closed => closed += 1,
            Status::Blocked => blocked += 1,
            _ => open += 1,
        }
    }

    println!("open={} closed={} blocked={}", open, closed, blocked);
}

