}

impl Config {
    fn merge(base: &Config, layer: &Config) -> Config {
        Config {
            timeout: base.timeout.or(layer.timeout),
            retries: base.retries.or(layer.retries),
            endpoint: base.endpoint.or(layer.endpoint),
            log_json: base.log_json.or(layer.log_json),
        }
    }

    fn to_map(&self) -> BTreeMap<&'static str, String> {
        let mut out = BTreeMap::new();
        out.insert("timeout", self.timeout.unwrap_or(30).to_string());
        out.insert("retries", self.retries.unwrap_or(2).to_string());
        out.insert(
            "endpoint",
