use std::fmt;

#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

impl fmt::Display for Booking {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.id)
    }
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn first_conflict<'a>(accepted: &'a [Booking], candidate: &Booking) -> Option<&'a Booking> {
    accepted.iter().find(|existing| overlaps(existing, candidate))
}

fn summarize(bookings: &[Booking]) -> String {
    let mut accepted: Vec<Booking> = Vec::new();
    let mut conflicts: Vec<String> = Vec::new();

    for booking in bookings {
        if booking.start > booking.end {
            continue;
        }

        if let Some(existing) = first_conflict(&accepted, booking) {
            conflicts.push(format!("{}->{}", existing.id, booking.id));
        } else {
            accepted.push(*booking);
        }
    }

    let accepted_ids = accepted
        .iter()
        .map(|b| b.id)
        .collect::<Vec<_>>()
        .join(", ");
    let conflict_ids = conflicts.join(", ");

    format!("accepted: [{}]\nconflicts: [{}]", accepted_ids, conflict_ids)
}

