use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event {
    Open,
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

struct Ticket {
    status: Status,
    blockers: u8,
}

fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Open => {
            ticket.status = Status::Open;
        }
        Event::Start => {
            if !matches!(ticket.status, Status::Closed) {
                ticket.status = Status::InProgress;
            }
        }
        Event::Block => {
            ticket.blockers += 1;
            ticket.status = Status::Blocked;
        }
        Event::Unblock => {
            if ticket.blockers > 0 {
                ticket.blockers -= 1;
            }
            ticket.status = Status::Open;
        }
        Event::Resolve => {
            ticket.status = Status::Resolved;
        }
        Event::Reopen => {
            ticket.status = Status::Open;
        }
        Event::Close => {
            ticket.status = Status::Closed;
        }
    }
}

fn status_name(status: Status) -> &'static str {
    match status {
        Status::New => "new",
        Status::Open => "open",
        Status::InProgress => "in_progress",
        Status::Blocked => "blocked",
        Status::Resolved => "resolved",
        Status::Closed => "closed",
    }
}

fn main() {
    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    let events = [
        ("A", Event::Open),
        ("A", Event::Start),
        ("A", Event::Block),
        ("A", Event::Resolve),
        ("A", Event::Unblock),
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Open),
        ("B", Event::Close),
        ("B", Event::Reopen),
        ("B", Event::Start),
        ("B", Event::Resolve),
        ("B", Event::Close),
        ("C", Event::Open),
        ("C", Event::Block),
        ("C", Event::Unblock),
        ("D", Event::Open),
        ("D", Event::Start),
        ("D", Event::Resolve),
        ("D", Event::Reopen),
        ("D", Event::Resolve),
        ("D", Event::Close),
    ];

    for (id, event) in events {
        let ticket = tickets.entry(id).or_insert(Ticket {
            status: Status::New,
            blockers: 0,
        });
        apply(ticket, event);
    }

    for (id, ticket) in tickets {
        println!("{}:{}:{}", id, status_name(ticket.status), ticket.blockers);
    }
}

