use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Done,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Blocked => "blocked",
            Status::Done => "done",
        }
    }
}

enum Event {
    Start,
    Block,
    Unblock,
    Finish,
    Reopen,
}

struct TicketReport {
    id: &'static str,
    history: Vec<Status>,
    final_status: Status,
    reopened: usize,
    blocked_count: usize,
    invalid: usize,
}

fn apply_event(status: Status, event: Event) -> Option<Status> {
    match (status, event) {
        (Status::Open, Event::Start) => Some(Status::InProgress),
        (Status::Open, Event::Block) => Some(Status::Blocked),
        (Status::Open, Event::Finish) => Some(Status::Done),
        (Status::InProgress, Event::Block) => Some(Status::Blocked),
        (Status::InProgress, Event::Finish) => Some(Status::Done),
        (Status::Blocked, Event::Unblock) => Some(Status::InProgress),
        (Status::Blocked, Event::Finish) => Some(Status::Done),
        (Status::Done, Event::Reopen) => Some(Status::Open),
        _ => None,
    }
}

fn process(id: &'static str, events: &[Event]) -> TicketReport {
    let mut status = Status::Open;
    let mut history = vec![status];
    let mut reopened = 0;
    let mut blocked_count = 0;
    let mut invalid = 0;

    for event in events {
        match event {
            Event::Block => blocked_count += 1,
            Event::Reopen => {
                if status == Status::Done {
                    reopened += 1;
                }
            }
            _ => {}
        }

        if let Some(next) = apply_event(status, match event {
            Event::Start => Event::Start,
            Event::Block => Event::Block,
            Event::Unblock => Event::Unblock,
            Event::Finish => Event::Finish,
            Event::Reopen => Event::Reopen,
        }) {
            status = next;
            history.push(status);
        } else {
            invalid += 1;
        }
    }

    TicketReport {
        id,
        history,
        final_status: status,
        reopened,
        blocked_count,
        invalid,
    }
}

fn main() {
    let reports = vec![
        process(
            "A1",
            &[
                Event::Start,
                Event::Block,
                Event::Unblock,
                Event::Finish,
                Event::Reopen,
                Event::Start,
                Event::Finish,
            ],
        ),
        process("B2", &[Event::Block, Event::Finish]),
        process(
            "C3",
            &[
                Event::Finish,
                Event::Reopen,
                Event::Start,
                Event::Finish,
            ],
        ),
    ];

    let mut counts: BTreeMap<&'static str, usize> = BTreeMap::new();
    let mut invalid_total = 0;

    for report in &reports {
        let key = report.final_status.as_str();
        *counts.entry(key).or_insert(0) += 1;
        invalid_total += report.invalid;

        let path = report
            .history
            .iter()
            .map(|s| s.as_str())
            .collect::<Vec<_>>()
            .join(" -> ");

        println!(
            "{} {} | final={} reopened={} blocked={} invalid={}",
            report.id,
            path,
            report.final_status.as_str(),
            report.reopened,
            report.blocked_count,
            report.invalid
        );
    }

    println!(
        "SUMMARY done={} blocked={} open={} invalid_events={}",
        counts.get("done").copied().unwrap_or(0),
        counts.get("blocked").copied().unwrap_or(0),
        counts.get("open").copied().unwrap_or(0),
        invalid_total
    );
}

fn parse_hhmm(s: &str) -> u32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<u32>().unwrap() * 60 + m.parse::<u32>().unwrap()
}

#[derive(Clone, Debug)]
struct Booking {
    start: u32,
    end: u32,
    label: &'static str,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start < b.end && b.start < a.end
}

fn fmt_hhmm(v: u32) -> String {
    format!("{:02}:{:02}", v / 60, v % 60)
}

fn main() {
    let requests = [
        ("09:00", "10:30", "A"),
        ("10:15", "11:00", "B"),
        ("10:30", "11:00", "C"),
        ("08:45", "09:00", "D"),
        ("08:50", "09:10", "E"),
        ("11:00", "12:00", "F"),
        ("10:00", "10:30", "G"),
        ("12:00", "12:15", "H"),
        ("11:30", "12:00", "I"),
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut accepted_count = 0;
    let mut rejected_count = 0;

    for (start, end, label) in requests {
        let candidate = Booking {
            start: parse_hhmm(start),
            end: parse_hhmm(end),
            label,
        };

        let conflicts: Vec<&str> = accepted
            .iter()
            .filter(|b| overlaps(&candidate, b))
            .map(|b| b.label)
            .collect();

        if conflicts.is_empty() {
            println!(
                "accepted {}-{} {}",
                fmt_hhmm(candidate.start),
                fmt_hhmm(candidate.end),
                candidate.label
            );
            accepted.push(candidate);
            accepted_count += 1;
        } else {
            println!(
                "rejected {}-{} {} conflicts {}",
                fmt_hhmm(candidate.start),
                fmt_hhmm(candidate.end),
                candidate.label,
                conflicts.join(",")
            );
            rejected_count += 1;
        }
    }

    print!("accepted={} rejected={}", accepted_count, rejected_count);
}
